window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q12"]=window.__LIBQ["tien-nghich"]["q12"]||{};window.__LIBQ["tien-nghich"]["q12"]["artifacts"]={"updatedAt":"2026-07-13","count":58,"artifacts":[{"id":"chi-bao-chu-tuoc-toc","name":"Chí bảo Chu Tước tộc","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo","soHuu":["Nghiệt Tước đời thứ ba"],"trangThai":"bi-cuop","blurb":"Chí bảo truyền đời của Chu Tước tộc, nguyên thuộc Lão Tổ Chu Tước đời đầu tiên. Bị Nghiệt Tước đời thứ ba trộm mang đi khi phản bội, dùng làm nền tảng lập nên Hỏa Tước tộc. Tên gọi cụ thể và công năng chi tiết chưa được tiết lộ.","detail":"Chí bảo này vốn thuộc về Lão Tổ Chu Tước đời đầu tiên, được xem là bảo vật trọng yếu nhất của toàn tộc. Nghiệt Tước đời thứ ba đã trộm chí bảo này rồi bỏ trốn, lấy đó làm nền tảng khai sáng Hỏa Tước tộc. Lão Tổ đời đầu vì bị phong ấn nên không thể thanh lý môn hộ đòi lại bảo vật. Sự kiện này được chính Lão Tổ đời đầu tiết lộ (@c1325). Tên gọi cụ thể của chí bảo cũng như công năng chi tiết đều chưa được trình bày trong nguyên tác tính tới mốc hiện có.","chuSoHuu":[{"ten":"Điên Lạc đại đế","tuChuong":"@c1325","denChuong":"","cachCoDuoc":"Chủ nhân gốc","trangThai":"bi-cuop"},{"ten":"Nghiệt Tước đời thứ ba","tuChuong":"@c1325","denChuong":"","cachCoDuoc":"Trộm","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1325","loai":"doi-chu","importance":"major","giaiDoan":"Hé lộ nguồn gốc","text":"Lão tổ đời đầu tiết lộ Nghiệt Tước đời thứ ba trộm chí bảo rồi trốn đi lập Hỏa Tước tộc. Lão tổ bị phong ấn không thể thanh lý.","anchor":"Nghiệt tước đời thứ ba trộm chí bảo của ta rồi trốn đi, lập thành Hỏa Tước tộc"}]},"nguon":["@c1325"]},{"id":"long-chim-chin-mau-sam-la-hoa","name":"Lông chim chín màu (Sâm La Hỏa)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo cấp","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Chiếc lông chim chín màu do Chu Tước đời đầu tiên ngưng tụ từ Sâm La Hỏa của lão, hóa thành từ mi tâm pho tượng và trao cho Vương Lâm. Đây là vật phòng thân có thể bảo vệ tính mạng trước Nghiệt tước đời thứ ba.","detail":"Lông chim chín màu vốn là kết tinh của Sâm La Hỏa thuộc về Chu Tước đời đầu tiên. Tại mi tâm pho tượng của Chu Tước đời đầu, lão đã ngưng tụ Sâm La Hỏa hóa thành chiếc lông chim chín màu rực rỡ và tặng cho Vương Lâm làm vật hộ mệnh. Bản chất của chiếc lông chim này chính là Sâm La Hỏa của Chu Tước đời đầu, mang uy lực đủ sức bảo vệ tính mạng trước mối đe dọa từ Nghiệt tước đời thứ ba.","phanLoaiPhu":"Lông chim linh bảo","nguonGoc":"Do Chu Tước đời đầu tiên ngưng tụ từ Sâm La Hỏa của lão, từ mi tâm pho tượng hóa thành","uyLuc":"Có thể bảo vệ tính mạng trước Nghiệt tước đời thứ ba, nhờ bản chất là Sâm La Hỏa của Chu Tước đời đầu tiên.","dacDiem":"Chín màu rực rỡ, bản chất là Sâm La Hỏa của Chu Tước đời đầu tiên, hóa thành từ mi tâm pho tượng.","chuHienThoi":"Vương Lâm","congNang":["Bảo vệ tính mạng trước Nghiệt tước đời thứ ba @c1328"],"chuSoHuu":[{"ten":"Chu Tước đời đầu (Điên Lạc đại đế)","tuChuong":"@c1328","denChuong":"@c1328","cachCoDuoc":"Tự ngưng tụ từ Sâm La Hỏa","trangThai":"da-tang"},{"ten":"Vương Lâm","tuChuong":"@c1328","denChuong":"","cachCoDuoc":"Được Chu Tước đời đầu tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1328","loai":"xuat-hien","importance":"major","giaiDoan":"Chu Tước đời đầu tặng cho Vương Lâm","text":"Chu Tước đời đầu từ mi tâm pho tượng hóa thành chiếc lông chim chín màu ngưng tụ Sâm La Hỏa, tặng Vương Lâm làm lợi khí phòng thân trước Nghiệt tước đời thứ ba.","anchor":"Vật này ngưng tụ Sâm La Hỏa của lão phu"}]},"nguon":["@c1328"]},{"id":"chi-bao-chu-tuoc-toc-khau-quyet","name":"Khẩu quyết chí bảo Chu Tước tộc","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Khẩu quyết điều khiển chí bảo Chu Tước tộc, do Chu Tước đời đầu truyền vào linh hồn Vương Lâm. Chí bảo đang trong tay Nghiệt tước đời thứ ba nhưng hắn không biết cách dùng.","detail":"Chu Tước đời đầu truyền khẩu quyết điều khiển chí bảo Chu Tước tộc cho Vương Lâm, ghi thẳng vào linh hồn. Chí bảo đang trong tay Nghiệt tước đời thứ ba nhưng hắn không biết phương pháp điều khiển. Nếu Vương Lâm đoạt lại được thì cho luôn.","nguonGoc":"Chu Tước đời đầu truyền lại","congNang":["Điều khiển chí bảo Chu Tước tộc"],"tabs":{"tienTrinh":[{"chuong":"@c1328","loai":"xuat-hien","importance":"normal","giaiDoan":"Chu Tước đời đầu truyền cho Vương Lâm","text":"Chu Tước đời đầu truyền khẩu quyết điều khiển chí bảo Chu Tước tộc vào linh hồn Vương Lâm, chí bảo đang trong tay Nghiệt tước đời thứ ba nhưng hắn không biết cách dùng.","anchor":"Phương pháp điều khiển vật ấy nghiệt tước đời thứ ba không biết"}]},"nguon":["@c1328"]},{"id":"khoi-thu-cot","name":"Khối thú cốt","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Khối thú cốt lớn bằng bàn tay, là nguyên nhân Tư Mã Mặc năm xưa bị đuổi khỏi Phá Thiên Tông. Vương Lâm dùng để kích động tâm tình Tư Mặc Tử.","detail":"Khối thú cốt lớn bằng bàn tay, liên quan trực tiếp đến việc Tư Mã Mặc bị trục xuất khỏi Phá Thiên Tông năm đó. Vương Lâm rút từ khe trữ vật, cùng ngọc bội Phá Thiên Tông sử dụng như vũ khí công tâm nhằm kích động tâm tình đối phương khiến hư hỏa bùng phát.","congNang":["Vật chứng khiến Tư Mã Mặc bị trục xuất khỏi Phá Thiên Tông, dùng làm vũ khí công tâm"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1330","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1330","loai":"dùng","importance":"normal","giaiDoan":"Dùng công tâm Tư Mặc Tử","text":"Vương Lâm rút khối thú cốt cùng ngọc bội Phá Thiên Tông để kích động tâm tình Tư Mặc Tử, khiến hư hỏa bùng lên dữ dội.","anchor":"Đây chính là nguyên nhân Tư Mặc Tử năm đó bị đuổi khỏi Phá Thiên Tông"}]},"nguon":["@c1330"]},{"id":"truong-thuong-hu-thuc-co-ma-hon","name":"Trường thương hư thực (Cổ Ma Hồn)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Cổ Ma Hồn","Vương Lâm"],"trangThai":"dang-dung","blurb":"Thanh trường thương hư hư thực thực do Cổ Ma Hồn triệu ra khi được Vương Lâm phóng thích chiến đấu.","detail":"Cổ Ma Hồn hóa hình người nhỏ bé, triệu trường thương hư thực cuốn lấy thân lao thẳng đến Tư Mặc Tử.","congNang":["Vũ khí tấn công của Cổ Ma Hồn"],"tabs":{"tienTrinh":[{"chuong":"@c1331","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Cổ Ma Hồn triệu trường thương hư thực tấn công Tư Mặc Tử.","anchor":"lập tức liền có một thanh trường thương hư hư thực thực bất chợt hiện ra"}]},"capNhatToi":"@c1331","dinhDanh":"goc","nguon":["@c1331"]},{"id":"dai-lua-trang-vet-mau-hoa-mai","name":"Dải lụa trắng vết máu hoa mai","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tư Mặc Tử"],"trangThai":"dang-co","blurb":"Dải lụa trắng có vết máu tươi hình hoa mai, khi vung lên hóa thành đám sương đỏ, bên trong xuất hiện nữ tử lụa trắng có sức mạnh tuế nguyệt.","detail":"Dải lụa trắng có vết máu tươi hình hoa mai cực kỳ kinh người. Khi Tư Mặc Tử vung lên, dải lụa hóa thành đám sương đỏ, bên trong xuất hiện một thân ảnh nữ tử uyển chuyển mặc lụa trắng.","congNang":["Triệu hồi hồn/phân thân nữ tử có sức mạnh tuế nguyệt"],"hinhDang":"Dải lụa trắng có vết máu tươi hình hoa mai","chuHienThoi":"Tư Mặc Tử","chuSoHuu":[{"ten":"Tư Mặc Tử","tuChuong":"@c1332","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1332","loai":"xuat hien","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Tư Mặc Tử vung dải lụa triệu hồi nữ tử lụa trắng phóng sức mạnh tuế nguyệt bao vây Cổ Ma Hồn.","anchor":"trên dải lụa này còn có một vết máu tươi giống như là một bông hoa mai"}]},"capNhatToi":"@c1332","nguon":["@c1332"]},{"id":"dai-lua-trang-tieu-lan","name":"Dải lụa trắng (của Tiểu Lan)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Tư Mặc Tử"],"trangThai":"đang sử dụng","blurb":"Dải lụa trắng nguyên là vật Tiểu Lan dùng tự vẫn sau khi bị mã phỉ lăng nhục. Hồn phách nàng lưu lại bên trong, được Tư Mặc Tử giữ trong ngực suốt đời. Chưởng Tôn dụ dẫn Tư Mã Mặc bằng lời hứa có thể khiến muội muội ngưng hóa thành hình nhờ dải lụa này.","detail":"Dải lụa trắng vốn là vật Tiểu Lan dùng để tự vẫn sau khi bị mã phỉ lăng nhục. Tư Mã Mặc cảm nhận hồn phách muội muội vẫn tồn tại bên trong dải lụa, nên giữ bên ngực không rời suốt đời. Chưởng Tôn lấy đó làm mồi dụ Tư Mã Mặc đi theo, hứa hẹn rằng dải lụa có thể khiến muội muội ngưng hóa thành hình, theo cạnh hắn vĩnh hằng, thậm chí nếu tăng tu vi còn có thể sống lại. Khi Vương Lâm phá Thiên Hoàng Lô, hư ảnh thiếu nữ từng xuất hiện và được Tư Mặc Tử thu vào tay áo.","congNang":["Chứa hồn phách Tiểu Lan bên trong dải lụa @c1334","Có thể ngưng hóa hồn phách thành hình, khiến muội muội hiện hình theo cạnh chủ nhân @c1334"],"chuSoHuu":[{"ten":"Tư Mặc Tử","tuChuong":"@c1334","denChuong":"","cachCoDuoc":"Giữ lại từ thi thể muội muội","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1334","loai":"xuất hiện","importance":"major","giaiDoan":"Hé lộ nguồn gốc và ý nghĩa","text":"Lộ nguồn gốc là vật Tiểu Lan tự vẫn, hồn phách nàng lưu bên trong. Chưởng Tôn hứa có thể khiến muội muội ngưng hóa thành hình. Khi Thiên Hoàng Lô phá, hư ảnh thiếu nữ xuất hiện và được Tư Mặc Tử thu vào tay áo.","anchor":"Ở đó hắn có thể cảm nhận được hồn phách muội muội dường như vẫn luôn ở trong dải lụa này"}]},"nguon":["@c1334"]},{"id":"mai-rua-co-hon-cam","name":"Mai rùa Cổ Hồn Cấm","cn":null,"aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cấm khí (cổ vật Chu Tước tộc)","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm nhận, tự nghiên cứu","blurb":"Mai rùa chứa cấm chế Cổ Hồn Cấm do lão tổ đời đầu Chu Tước tộc để lại, Lão Chu Tước tách ra giao Vương Lâm phòng thân.","detail":"Lão Chu Tước triệu một con rùa lớn giữa không trung, bấm quyết thu nhỏ thành mai rùa to bằng bàn tay, phát u quang vạn trượng chói mắt như ánh trăng bao phủ trời đất. Bên trong chứa cấm chế Cổ Hồn Cấm — cấm thuật do lão tổ đời đầu tiên Chu Tước tộc để lại. Lão Chu Tước bản thân không có phương pháp tu luyện Cổ Hồn Cấm, nên tách cấm chế ra ném cho Vương Lâm để phòng thân, khuyên hắn có thời gian hãy tự nghiên cứu.","nguon":["@c1335"]},{"id":"ngoc-gian-phan-gioi-co-tan","name":"Ngọc giản Phần Giới Cổ Tán","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Lão Chu Tước","Vương Lâm"],"trangThai":"Đã hủy","blurb":"Ngọc giản do Lão Chu Tước trao cho Vương Lâm, chứa toàn bộ ấn quyết và thuật mở ô của Phần Giới Cổ Tán. Vương Lâm khắc nhớ xong liền hủy, ngọc giản vỡ thành tro bụi.","detail":"Lưu trữ đầy đủ bốn lần ấn quyết cùng phương pháp mở ô của thần thông Phần Giới Cổ Tán. Lão Chu Tước dặn Vương Lâm nhớ kỹ rồi hủy. Vương Lâm dung nhập tâm thần vào ngọc giản, khắc sâu mọi ấn quyết vào tâm trí, sau đó hủy ngọc giản — tro bụi bay về phía chân trời.","congNang":["Lưu trữ toàn bộ ấn quyết và phương pháp mở ô Phần Giới Cổ Tán"],"capNhatToi":"@c1336","chuSoHuu":[{"ten":"Lão Chu Tước","tuChuong":"@c1336","denChuong":"@c1336","cachCoDuoc":"Sở hữu sẵn","trangThai":"Đã trao"},{"ten":"Vương Lâm","tuChuong":"@c1336","denChuong":"@c1336","cachCoDuoc":"Lão Chu Tước trao","trangThai":"Đã hủy sau khi khắc nhớ"}],"tabs":{"tienTrinh":[{"chuong":"@c1336","loai":"doi-chu","importance":"normal","giaiDoan":"Trao và hủy","text":"Lão Chu Tước trao ngọc giản cho Vương Lâm. Vương Lâm khắc sâu toàn bộ ấn quyết rồi hủy, ngọc giản vỡ thành tro bụi bay về phía chân trời.","anchor":"Trong ngọc giản này chính là toàn bộ ấn quyết, còn có thuật mở ô"}]},"nguon":["@c1336"]},{"id":"ngon-lua-bay-mau-bang-nam-tay","name":"Ngọn lửa bảy màu bằng nắm tay","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Lão tổ Hỏa Tước tộc"],"trangThai":"da-dung","blurb":"Ngọn lửa bảy màu to bằng nắm tay do thân ảnh bí ẩn phóng ra thưởng cho lão tổ Hỏa Tước tộc, dung nhập vào mi tâm.","detail":"Thân ảnh bí ẩn trong thánh địa phóng ra ban cho lão tổ Hỏa Tước tộc như phần thưởng vì dâng Chu Tước đời thứ sáu (giả). Ngọn lửa lao thẳng vào mi tâm lão tổ và dung nhập vào bên trong.","nguon":["@c1337"]},{"id":"co-ma-hon","name":"Cổ Ma Hồn","cn":"古魔魂","aliases":[],"category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Cổ Ma Hồn là hồn phách Cổ Ma được Vương Lâm xóa sạch thần trí, dùng để thế chỗ hồn phách bản thân nhằm chống lại thuật đoạt hồn. Khi Chưởng Tôn thi triển Mò Trăng Đáy Giếng, thứ bị mò ra là Cổ Ma Hồn chứ không phải hồn thật của Vương Lâm, nhờ đó hắn giữ được tính mạng.","detail":"Vương Lâm xóa thần trí của Cổ Ma Hồn rồi dùng nó thế chỗ hồn phách bản thân. Sở dĩ việc thay thế hoàn hảo không bị phát hiện là vì Cổ Thần và Cổ Ma đồng nguyên, hồn phách hai bên có thể tương thông. Khi Chưởng Tôn dùng thuật Mò Trăng Đáy Giếng mò hồn Vương Lâm, thứ bị kéo ra là Cổ Ma Hồn. Chưởng Tôn bóp nát Cổ Ma Hồn, Vương Lâm bị tổn thương — toàn thân run rẩy, sắc mặt tái nhợt — nhưng vẫn sống sót, tránh được kết cục bị đoạt hồn.","congNang":["Thay thế hồn phách bản thân để chống thuật đoạt hồn; khi bị mò hồn, Cổ Ma Hồn bị lấy ra thay cho hồn thật @c1338"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1338","denChuong":"@c1338","cachCoDuoc":"Sở hữu sẵn (Cổ Thần đồng nguyên Cổ Ma)","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1338","loai":"dùng","importance":"major","giaiDoan":"Bị sử dụng và hủy","text":"Vương Lâm xóa thần trí Cổ Ma Hồn thế chỗ hồn phách bản thân, khiến thuật Mò Trăng Đáy Giếng của Chưởng Tôn mò trúng Cổ Ma Hồn. Cổ Ma Hồn bị bóp nát, Vương Lâm tổn thương nhưng sống.","anchor":"hắn xóa đi thần trí của Cổ Ma Hồn, thế chỗ cho hồn phách của bản thân"}]},"nguon":["@c1338"],"dacDiem":"Cổ Thần và Cổ Ma đồng nguyên, nên Cổ Ma Hồn sau khi bị xóa thần trí có thể thế chỗ hồn phách bản thân một cách hoàn hảo, không bị phát giác. Khi Cổ Ma Hồn bị hủy, chủ nhân vẫn chịu tổn thương nhất định nhưng không mất mạng."},{"id":"ao-giap-thai-co-chi-bao","name":"Áo giáp thái cổ chí bảo (của Chưởng Tôn)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thái cổ chí bảo","soHuu":["Chưởng Tôn"],"trangThai":"hong","blurb":"Thái cổ chí bảo do Chưởng Tôn nhận từ sư tôn, thường ngày dung hợp trên thân thể như áo giáp bảo hộ. Khi cần tấn công có thể tách ra hóa thành bàn tay khổng lồ che trời, đủ sức đối kháng Phần Giới Cổ Tán chưa mở hoàn toàn, song cuối cùng bị Cổ Tán tự hủy cuốn tan vỡ.","detail":"Tấm áo giáp này là một thái cổ chí bảo, nguồn gốc từ sư tôn của Chưởng Tôn truyền lại. Bình thường nó dung hợp trực tiếp trên thân thể Chưởng Tôn, đóng vai trò phòng ngự. Trong trận chiến với Phần Giới Cổ Tán, Chưởng Tôn xé áo giáp khỏi thân, khiến nó biến hóa thành bàn tay khổng lồ che trời để đối kháng. Bàn tay khổng lồ xuyên thấu hỏa khí đánh lên chiếc ô, thể hiện uy lực công phá đáng kể trước một Cổ Tán chưa hoàn toàn mở ra. Tuy nhiên, khi Phần Giới Cổ Tán phát động tự hủy, áo giáp bị sức mạnh tự hủy cuốn tan vỡ, không còn tồn tại.","nguonGoc":"Sư tôn của Chưởng Tôn","hinhDang":"Áo giáp dung hợp trên thân thể","congNang":["Dung hợp trên thân thể Chưởng Tôn, đóng vai trò áo giáp bảo hộ","Tách khỏi thân biến thành bàn tay khổng lồ che trời để tấn công, xuyên thấu hỏa khí đánh lên mục tiêu @c1340"],"uyLuc":"Đủ sức đối kháng Phần Giới Cổ Tán chưa mở hoàn toàn, bàn tay khổng lồ xuyên thấu hỏa khí đánh lên chiếc ô, nhưng cuối cùng bị Cổ Tán tự hủy cuốn tan vỡ.","chuSoHuu":[{"ten":"Chưởng Tôn","tuChuong":"@c1340","denChuong":"@c1340","cachCoDuoc":"Lấy từ sư tôn","trangThai":"hong"}],"tabs":{"tienTrinh":[{"chuong":"@c1340","loai":"dùng","importance":"major","giaiDoan":"Xuất hiện và bị hủy","text":"Chưởng Tôn xé áo giáp khỏi thân biến thành bàn tay khổng lồ đối kháng Phần Giới Cổ Tán. Bị Cổ Tán tự hủy cuốn tan vỡ.","anchor":"Áo giáp này là lão phu lấy được từ sư tôn, là một thái cổ chí bảo"}]},"nguon":["@c1340"]},{"id":"co-than-ho-ti","name":"Cổ Thần hộ tí","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Hộ tí luyện từ xương Cổ Thần, gắn trên cánh tay phải Vương Lâm, dùng để phòng ngự bên ngoài thân thể và kích hoạt Thuật bảo mệnh bát tinh Cổ Thần.","detail":"Cổ Thần hộ tí là pháp khí luyện từ xương Cổ Thần, gắn trên cánh tay phải Vương Lâm. Khi kích hoạt, khí tức Cổ Thần tràn ra hóa thành hộ tí bao bọc bên ngoài, mang công năng phòng ngự. Ngoài ra, hộ tí còn là chìa khóa kích hoạt Thuật bảo mệnh bát tinh Cổ Thần — cổ chi tí hữu — triệu hoán Cổ Thần hư ảo tham chiến. Sau khi Cổ Thần hư ảo tiêu tan, hộ tí dung nhập trở lại tay phải. Tại @c1340, Vương Lâm dùng hộ tí kích hoạt thuật bảo mệnh, triệu hoán Cổ Thần hư ảo đánh trọng thương đối thủ.","vatLieu":"Xương Cổ Thần","congNang":["Phòng ngự bên ngoài thân thể: khí tức Cổ Thần tràn ra hóa thành hộ tí bao bọc cánh tay, chống đỡ công kích","Kích hoạt Thuật bảo mệnh bát tinh Cổ Thần, triệu hoán Cổ Thần hư ảo tham chiến @c1340"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1340","denChuong":"","cachCoDuoc":"Tự luyện từ xương Cổ Thần","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1340","loai":"dùng","importance":"major","giaiDoan":"Kích hoạt thuật bảo mệnh","text":"Vương Lâm dùng Cổ Thần hộ tí kích hoạt Thuật bảo mệnh bát tinh Cổ Thần, triệu hoán Cổ Thần hư ảo đánh trọng thương Chưởng Tôn. Hộ tí sau đó dung nhập trở lại tay phải.","anchor":"một pháp khí được luyện từ xương của Cổ Thần"}]},"nguon":["@c1340"],"uyLuc":"Triệu hoán Cổ Thần hư ảo đánh trọng thương đối thủ @c1340","dacDiem":"Luyện từ xương Cổ Thần, gắn cố định trên cánh tay phải Vương Lâm; sau khi Cổ Thần hư ảo tiêu tan, hộ tí tự dung nhập trở lại tay phải"},{"id":"ngoc-gian-nu-tu-than-bi","name":"Ngọc giản của nữ tử thần bí (Vân Hải Tinh vực)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ngọc giản chứa nhiều cấm chế siêu việt không thuộc giới này, do nữ tử thần bí ở cái khe tầng chín Vân Hải Tinh vực đưa cho Vương Lâm. Mở ở giới ngoại có thể tránh Phong Giới Đại Trận quay về cái khe.","detail":"Nữ tử thần bí đưa cho Vương Lâm ở cái khe tầng chín Vân Hải Tinh vực, nhờ hắn tìm một vùng đất. Bên trong có nhiều cấm chế siêu việt mà tu sĩ giới này không nắm giữ, đến từ thế giới khác. Vương Lâm đánh giá bảy phần có thể đưa hắn trở về giới nội, nhưng cần tu vi nhất định. Hắn chưa mở vì đang trọng thương và chưa rõ nữ tử bạn hay thù.","congNang":["Mở ở giới ngoại có thể tránh Phong Giới Đại Trận quay về cái khe tầng chín Vân Hải Tinh vực"],"dacDiem":"Cấm chế bên trong không thuộc tu sĩ giới này, đến từ thế giới khác","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1342","denChuong":"","cachCoDuoc":"Được nữ tử thần bí đưa","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1342","loai":"xuat-hien","importance":"normal","giaiDoan":"Được Vương Lâm nhớ tới như đường về thay thế","text":"Vương Lâm nhớ tới ngọc giản nữ tử thần bí đưa ở cái khe tầng chín Vân Hải Tinh vực, đánh giá bảy phần khả thi nhưng chưa dám mở vì trọng thương và chưa rõ bạn thù.","anchor":"cũng nói là ở giới ngoại mở ngọc giản này ra, có thể tránh Phong giới đại trận mà quay trở về bên trong cái khe"}]},"nguon":["@c1342"]},{"id":"mong-tay-den-dai-hoang-thuong-nhan","name":"Móng tay đen (của Đại Hoang thượng nhân)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Chiếc móng tay đen kịt do Đại Hoang thượng nhân tặng Vương Lâm, mang khí tức âm trầm thê lương. Khi vung ra có uy lực xuyên thấu và hạ độc tu sĩ Không Niết sơ kỳ, nhưng chỉ dùng được một lần rồi tan vỡ.","detail":"Móng tay đen là vật mà Đại Hoang thượng nhân tặng cho Vương Lâm trước mặt Lão Chu Tước. Bề ngoài đen kịt, phát ra tiếng kêu thê lương dưới ánh trăng cùng khí tức âm trầm. Tại chương @c1343, Vương Lâm vung móng tay đen phản kích bàn tay khổng lồ của đại hán Phụng Thiên lang tộc ở cảnh giới Không Niết sơ kỳ; chiếc móng xuyên thấu bàn tay đối phương, khiến cánh tay hóa bụi tiêu tan, đồng thời gây trúng độc làm chiến lực đối phương giảm ba thành. Uy lực vượt ngoài dự liệu của Vương Lâm, tuy nhiên sau khi sử dụng thì tan vỡ, thuộc loại pháp bảo dùng một lần.","congNang":["Xuyên thấu mục tiêu, khiến cánh tay tu sĩ Không Niết sơ kỳ hóa bụi tiêu tan @c1343","Hạ độc đối phương, giảm ba thành chiến lực @c1343"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1343","denChuong":"@c1343","cachCoDuoc":"Đại Hoang thượng nhân tặng","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1343","loai":"dung","importance":"major","giaiDoan":"Sử dụng và tan vỡ","text":"Vương Lâm vung móng tay đen phản kích bàn tay khổng lồ của đại hán Phụng Thiên lang tộc (Không Niết sơ kỳ), xuyên thấu phá hủy cánh tay và gây trúng độc giảm ba thành chiến lực. Sau khi dùng, móng tay tan vỡ.","anchor":"Chiếc móng tay này dấy lên một cơn hắc phong, va chạm với bàn tay kia"}]},"nguon":["@c1343"],"uyLuc":"Xuyên thấu bàn tay khổng lồ của tu sĩ Không Niết sơ kỳ, khiến cánh tay hóa bụi tiêu tan và gây trúng độc giảm ba thành chiến lực, uy lực vượt ngoài dự liệu của Vương Lâm.","dacDiem":"Đen kịt, phát tiếng kêu thê lương dưới ánh trăng, mang khí tức âm trầm; là pháp bảo dùng một lần, sử dụng xong liền tan vỡ."},{"id":"la-ban-nu-tu-phong-diet-toc","name":"La bàn (của nữ tử Phong Diệt tộc)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Thiếu nữ Phong Diệt tộc"],"trangThai":"đang dùng","blurb":"La bàn nữ tử Phong Diệt tộc cầm trong tay, gõ vào để định vị chính xác vị trí Vương Lâm, chỉ ra phương hướng và khoảng cách cụ thể tới từng dặm.","detail":"Nữ tử gõ vào la bàn để xác định chính xác vị trí Vương Lâm trong Thái Cổ tinh thần, báo cả phương hướng và số dặm cụ thể cho đại hán Phụng Thiên lang tộc truy kích.","congNang":["Định vị mục tiêu chính xác (phương hướng + khoảng cách)","Truy tìm vị trí mục tiêu với độ chính xác đến từng dặm"],"nguon":["@c1343","@c1344"],"tabs":{"tienTrinh":[{"chuong":"@c1344","loai":"dùng","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Thiếu nữ dùng la bàn xác định vị trí Vương Lâm ở phía Đông Bắc cách 173 vạn 4532 dặm, chính là hướng cổ mộ.","anchor":"Phía Đông Bắc, trong một trăm bảy mươi ba vạn, bốn ngàn năm trăm ba mươi hai dặm"}]},"aliases":["La bàn (của thiếu nữ Phong Diệt tộc)"],"chuSoHuu":[{"ten":"Thiếu nữ Phong Diệt tộc","tuChuong":"@c1344","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}]},{"id":"gieng-nuoc-cung-dien","name":"Giếng nước trong cung điện","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Không rõ","soHuu":["Lão già hắc bào (trong đại điện)"],"trangThai":"dang-co","blurb":"Giếng nước nằm trong cung điện u ám trôi nổi giữa tinh không Thái Cổ Tinh Thần, mặt nước tĩnh lặng trong suốt như gương. Là bộ phận cốt lõi của thuật Tĩnh Trung Lao Nguyệt, kết hợp ba ngọn nến để phản chiếu và phong ấn thân ảnh mục tiêu nhằm thao túng từ xa.","detail":"Giếng nằm trên mặt đất bên trong một cung điện lớn u ám, trôi nổi giữa vùng tinh không vô biên của Thái Cổ Tinh Thần. Mặt nước trong suốt như gương, phản xạ hình ảnh ba ngọn nến cùng thân ảnh tóc bạc của Vương Lâm trong trạng thái bị phong ấn. Giếng đóng vai trò trung tâm trong việc thi triển thuật Tĩnh Trung Lao Nguyệt — mặt nước phản chiếu mục tiêu, phối hợp cùng ba ngọn nến để duy trì phong ấn và thao túng từ xa. Khi Vương Lâm bước vào sương mù, mặt nước giếng nổi sóng gợn, thân ảnh trong giếng vặn vẹo rồi tiêu tan, cho thấy sự liên kết trực tiếp giữa trạng thái của mục tiêu và hình ảnh phản chiếu trong giếng.","congNang":["Phản chiếu thân ảnh mục tiêu bị phong ấn, kết hợp ba ngọn nến để thi triển thuật Tĩnh Trung Lao Nguyệt, thao túng mục tiêu từ xa @c1346"],"tabs":{"tienTrinh":[{"chuong":"@c1346","loai":"dùng","importance":"major","giaiDoan":"Thao túng Vương Lâm thất bại","text":"Mặt nước giếng phản chiếu thân ảnh Vương Lâm bị ba ngọn nến phong ấn, phục vụ thuật Tĩnh Trung Lao Nguyệt. Khi mục tiêu vào sương mù, mặt nước nổi sóng, thân ảnh tiêu tan.","anchor":"trên mặt đất của cung điện này có một cái giếng, mặt nước trong giếng trong suốt như gương"}]},"capNhatToi":"@c1346","nguon":["@c1346"],"dacDiem":"Mặt nước tĩnh lặng trong suốt như gương, có thể nổi sóng gợn và khiến thân ảnh phản chiếu vặn vẹo tiêu tan khi trạng thái mục tiêu thay đổi @c1346"},{"id":"cay-quat-lon-ba-truong","name":"Cây quạt lớn ba trượng (pháp bảo Cổ Thần)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo Cổ Thần (không phải tuyệt hảo)","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Pháp bảo Cổ Thần hình cây quạt lớn ba trượng, Vương Lâm hư không chụp lấy từ trước đầu lâu Cổ Thần, nhận xét không phải tuyệt hảo.","detail":"Cây quạt lớn ba trượng nằm trước đầu lâu Cổ Thần trên đài cao trong biển sương mù. Vương Lâm hư không chụp lấy, nhận xét đây là pháp bảo Cổ Thần nhưng không phải tuyệt hảo, rồi thu lại.","congNang":["Chưa rõ công năng cụ thể"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1350","denChuong":"","cachCoDuoc":"Hư không chụp lấy từ trước đầu lâu Cổ Thần","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1350","loai":"đổi chủ","importance":"normal","giaiDoan":"Vương Lâm thu được","text":"Vương Lâm hư không chụp lấy cây quạt ba trượng từ trước đầu lâu Cổ Thần, nhận xét không phải tuyệt hảo rồi thu lại.","anchor":"Vật này là pháp bảo của Cổ Thần nhưng không phải là tuyệt hảo"}]},"nguon":["@c1350"]},{"id":"ban-tinh-cua-hua-phuc","name":"Bàn tính của Hứa Phúc","cn":"","aliases":["Bàn tính"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hứa Phúc"],"trangThai":"dang-co","blurb":"Bàn tính pháp bảo của Hứa Phúc, phát ra tiếng lách cách rồi vỡ tung, con tính bay ra hóa thành đoàn xoáy cấm chế khổng lồ dùng để phá phong ấn sương mù đỏ.","detail":"Pháp bảo hình bàn tính, khi kích hoạt thì vỡ tung ra, các con tính bay ra biến thành đoàn xoáy cấm chế khổng lồ. Hứa Phúc dùng nó tiến về phía sương mù đỏ trên lưng Cổ Thần.","nguon":["@c1354"]},{"id":"quat-long-chim","name":"Quạt lông chim","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tiêu Tĩnh"],"trangThai":"dang-co","blurb":"Quạt lông chim cầm trong tay văn sĩ trung niên Tiêu Tĩnh, chưa được sử dụng.","detail":"Pháp bảo cầm tay của Tiêu Tĩnh, chưa rõ công năng.","nguon":["@c1354"]},{"id":"chin-ngoc-gian-cua-tieu-tinh","name":"Chín ngọc giản (của Tiêu Tĩnh)","cn":"","category":"phap-bao","categoryLabel":"Pháp khí phá cấm","phamCap":"Không rõ","soHuu":["Tiêu Tĩnh"],"trangThai":"da-dung","blurb":"Chín chiếc ngọc giản phát u quang, xếp hình tròn, có thể khiến cấm chế Cổ Hồn cấm và Tuế Nguyệt cấm ngừng vận hành trong hai mươi nhịp thở.","detail":"Pháp khí đặc biệt của Tiêu Tĩnh. Chín chiếc ngọc giản phát ra u quang, khi xếp thành hình tròn có thể khiến Cổ Hồn cấm và Tuế Nguyệt cấm ngừng vận hành trong hai mươi nhịp thở, cho phép xé khe hở trên đám sương đỏ. Sau khi hết thời gian hiệu lực, hào quang tiêu tan và cấm chế phục hồi.","congNang":["Khiến cấm chế Cổ Hồn cấm và Tuế Nguyệt cấm ngừng vận hành trong hai mươi nhịp thở"],"chuSoHuu":[{"ten":"Tiêu Tĩnh","tuChuong":"@c1355","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1355","loai":"dùng","importance":"normal","giaiDoan":"Tiêu Tĩnh dùng phá cấm chế sương đỏ","text":"Tiêu Tĩnh lấy ra chín ngọc giản phát u quang xếp hình tròn, khiến Cổ Hồn cấm và Tuế Nguyệt cấm ngừng vận hành trong hai mươi nhịp thở, xé khe hở trên sương đỏ. Sau hai mươi nhịp thở, hào quang tiêu tan và cấm chế phục hồi.","anchor":"trong tay xuất hiện chín ngọc giản"}]},"nguon":["@c1355"]},{"id":"dai-cao-ba-ngan-truong","name":"Đài cao ba ngàn trượng","cn":"","category":"khac","categoryLabel":"Kiến trúc bí cảnh","phamCap":"Bậc ba (tím)","soHuu":[],"trangThai":"nang-cap","blurb":"Đài cao lơ lửng giữa không trung, ban đầu hai ngàn trượng màu đỏ sẫm, sau khi nạp đủ ký hiệu dấu ấn con số từ mi tâm tu sĩ tử vong thì nâng lên ba ngàn trượng đổi sắc tím, trông như đại lục nhỏ.","detail":"Bề mặt đài cao tích lũy 589 ký hiệu — dấu ấn con số từ mi tâm tu sĩ tử vong; khi tu sĩ chết, thân thể tan vỡ nhưng dấu ấn con số không tiêu tan mà hóa ký hiệu trôi nổi. Khi Vương Lâm nạp thêm hơn mười ký hiệu, đến ký hiệu thứ 11 thì đài cao chấn động, hút bụi đất từ thiên địa mở rộng từ hai ngàn lên ba ngàn trượng, đổi sắc từ đỏ sẫm sang tím. Khi đạt ba ngàn trượng, đài cao phóng khí tức dạng thần thức cưỡng chế nhập vào cơ thể người đứng trên, hóa thành hình ảnh ký ức dung hợp với ký ức Vương Lâm mà hắn hoàn toàn không thể phản kháng.","congNang":["Hấp thu dấu ấn con số từ mi tâm tu sĩ tử vong dưới dạng ký hiệu trôi nổi để tích lũy và nâng bậc @c1358","Khi đạt bậc mới, phóng khí tức dạng thần thức cưỡng chế nhập vào cơ thể người đứng trên, truyền hình ảnh ký ức bí ẩn dung hợp với ký ức của người đó mà không thể phản kháng @c1358"],"tabs":{"tienTrinh":[{"chuong":"@c1358","loai":"nang-cap","importance":"major","giaiDoan":"Nâng bậc từ đỏ sẫm (2000 trượng) lên tím (3000 trượng)","text":"Vương Lâm thu hơn mười ký hiệu trôi nổi nạp vào đài cao. Đến ký hiệu thứ 11 thì đài cao chấn động, hút bụi đất từ thiên địa mở rộng lên ba ngàn trượng, đổi sắc thành tím. Phóng khí tức dạng thần thức cưỡng nhập vào cơ thể Vương Lâm hóa thành hình ảnh ký ức.","anchor":"có một khí tức như thể thần thức từ bên trong đài cao này tràn ra, theo hai chân Vương Lâm, trực tiếp tiến vào cơ thể hắn, hóa thành những hình ảnh"}]},"nguon":["@c1358"]},{"id":"tu-pham-dao-linh","name":"Tứ phẩm đạo linh","category":"khac","categoryLabel":"Khác","phamCap":"Tứ phẩm","soHuu":["Vương Lâm"],"trangThai":"bị thu trong Thiên Hoàng Lô","blurb":"Đạo linh hình kỳ lân phẩm cấp tứ phẩm, bị phong ấn trong lớp sương mù bên trong Thiên Hoàng Lô. Đã giao chiến với Linh Động Thượng Nhân khiến hắn bại trận, sau bị Vương Lâm thu phục.","detail":"Đạo linh có hình dạng kỳ lân, bị phong ấn bên trong lớp sương mù trong Thiên Hoàng Lô. Khi sương mù bị Vương Lâm xé mở, nó gầm rít lao ra tấn công nhưng va vào Thiên Hoàng Lô bị đẩy lùi. Trước đó đã giao chiến gian nan với Linh Động Thượng Nhân bên trong sương mù, trên người đầy vết thương. Bị Vương Lâm thu vào nơi khác trong Thiên Hoàng Lô.","nguon":["@c1359"]},{"id":"toc-an-linh-dong-toc","name":"Tộc ấn Linh Động Tộc","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Linh Động Thượng Nhân"],"trangThai":"dang-co","blurb":"Tộc ấn của Linh Động Tộc, tượng trưng cho quyền kế thừa tộc này. Lão già áo đen (tên thật Vương Lâm) trước khi chết đã trao tộc ấn cho Linh Động Thượng Nhân dù hắn không phải người trong tộc, vì đánh giá cao sự trung thành và thiên tư tuyệt vời của hắn.","detail":"Tộc ấn Linh Động Tộc là vật tượng trưng cho quyền kế thừa của Linh Động Tộc. Trong ký ức Linh Động, lão già áo đen bị trọng thương nặng, nguyên thần sắp tan vỡ, đã tự mình lấy tộc ấn ra trao cho Linh Động Thượng Nhân. Dù Linh Động không phải người trong tộc, lão già áo đen vẫn quyết định truyền tộc ấn cho hắn nhờ sự trung thành và thiên tư xuất chúng của hắn. Tên thật của lão già áo đen là Vương Lâm.","chuSoHuu":[{"ten":"Lão già áo đen trao tộc ấn","tuChuong":"@c1360","denChuong":"@c1360","cachCoDuoc":"Giữ tộc ấn ban đầu","trangThai":"da-trao"},{"ten":"Linh Động Thượng Nhân","tuChuong":"@c1360","denChuong":"","cachCoDuoc":"Được lão già áo đen trao trước khi chết","trangThai":"dang-co"}],"congNang":["Tượng trưng quyền kế thừa Linh Động Tộc @c1360"],"tabs":{"tienTrinh":[{"chuong":"@c1360","loai":"đổi chủ","importance":"major","giaiDoan":"Trao cho ngoại nhân","text":"Lão già áo đen (tên thật Vương Lâm) trước khi chết trao tộc ấn cho Linh Động Thượng Nhân dù hắn không phải người trong tộc.","anchor":"lão phu sẽ tự mình lấy tộc ấn ra đưa cho ngươi"}]},"capNhatToi":"@c1360","nguon":["@c1360"]},{"id":"dao-linh-giong-ky-lan","name":"Đạo linh giống kỳ lân","category":"khac","categoryLabel":"Thực thể bí ẩn","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"bị phong ấn trong Thiên Hoàng Lô","blurb":"Đạo linh có hình dáng giống kỳ lân, bị Vương Lâm phong ấn đơn độc trong một không gian bên trong Thiên Hoàng Lô. Toàn thân tràn ngập ngọn lửa, thương thế hồi phục với tốc độ cực kỳ kinh khủng; khi Vương Lâm dùng Lưu Nguyệt nghịch chuyển thời gian để bóc lộ bản chất, đã biến sắc kinh hãi.","detail":"Đạo linh giống kỳ lân xuất hiện khi Vương Lâm kiểm tra bên trong Thiên Hoàng Lô, nơi nó bị phong ấn đơn độc trong một không gian riêng biệt. Toàn thân sinh vật tràn ngập ngọn lửa, không ngừng gầm nhẹ. Dù mang thương thế, tốc độ hồi phục của nó cực kỳ kinh khủng, sắp hồi phục hoàn toàn. Vương Lâm lần đầu nhìn thấy không hiểu đạo linh là gì, bèn dùng Thông Thiên Môn thi triển Lưu Nguyệt nghịch chuyển thời gian, bóc từng lớp màn thần bí của sinh vật này; khi nhìn thấy bản chất thật thì biến sắc kinh hãi. Bản chất cụ thể của đạo linh chưa được tiết lộ tại thời điểm này (@c1361).","congNang":["Hồi phục thương thế với tốc độ cực kỳ kinh khủng, sắp hồi phục hoàn toàn dù đang mang trọng thương (@c1361)"],"tabs":{"tienTrinh":[{"chuong":"@c1361","loai":"xuất hiện","importance":"major","giaiDoan":"Bị phong ấn, Vương Lâm khám phá bản chất","text":"Bị phong ấn trong Thiên Hoàng Lô, toàn thân tràn ngập ngọn lửa, thương thế hồi phục cực nhanh. Vương Lâm dùng Thông Thiên Môn thi triển Lưu Nguyệt nghịch chuyển thời gian bóc từng lớp màn thần bí, nhìn thấy bản chất thì biến sắc kinh hãi thốt lên không thể nào.","anchor":"đạo linh giống như kỳ lân kia bị Vương Lâm phong ấn đơn độc ở đây, đang không ngừng gầm nhẹ"}]},"nguon":["@c1361"],"dacDiem":"Hình dáng giống kỳ lân, toàn thân tràn ngập ngọn lửa, không ngừng gầm nhẹ; bản chất thật ẩn sau nhiều lớp thần bí, khiến Vương Lâm biến sắc kinh hãi khi nhìn thấu qua Lưu Nguyệt (@c1361)."},{"id":"dan-duoc-tu-pham-dao-linh","name":"Đan dược tứ phẩm đạo linh","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Cực phẩm (do chín mặt trời hỗn mang luyện thành, sức mạnh đã tiêu tán hơn nửa sau phong ấn vạn năm)","soHuu":["Vương Lâm"],"trangThai":"Đang sở hữu, chưa đủ linh động, cần tế luyện","blurb":"Bản chất thật của tứ phẩm đạo linh — đan dược to bằng đầu người màu vàng, do người đạo bào bảy màu dung hợp chín mặt trời hỗn mang trong tinh không cổ xưa mà luyện thành. Mục đích ban đầu là nuôi dưỡng thiên đạo. Sau phong ấn vạn năm sức mạnh tiêu tán hơn nửa, biến thành dạng đạo linh.","detail":"Khi Vương Lâm dùng Lưu Nguyệt nghịch chuyển thời gian trên tứ phẩm đạo linh, đạo linh bốc hào quang vạn trượng, thân hình tiêu tan lộ ra dạng đan dược to bằng đầu người. Tiếp tục nghịch chuyển, đan dược vỡ, lộ ra tinh không cổ xưa không thuộc giới nội hay giới ngoại, bên trong có chín tinh cầu bốc cháy như mặt trời hỗn mang, được người đạo bào bảy màu vung tay dung hợp thành đan dược rồi phun khí bảy màu ép thành. Mục đích ban đầu là nuôi dưỡng thiên đạo. Sau phong ấn vạn năm sức mạnh tiêu tán hơn nửa, biến thành dạng đạo linh. Vương Lâm dùng Thiên Hoàng Lô luyện hóa ba ngày thu lại dạng đan dược kim quang vạn trượng, hút ngọn lửa từ đan dược tăng hỏa bổn nguyên, lôi đồ bắt đầu thiêu đốt tạp chất. Không dám nuốt trực tiếp vì sợ nổ tung thân Cổ Thần. Đan dược chưa đủ linh động, cần thứ gì đ","congNang":["Hút ngọn lửa từ đan dược tăng hỏa bổn nguyên, thiêu đốt tạp chất lôi đồ @c1362","Mục đích gốc: nuôi dưỡng thiên đạo @c1362"],"nguonGoc":"Chín mặt trời hỗn mang dung hợp bởi người đạo bào bảy màu trong tinh không cổ xưa","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1362","denChuong":"","cachCoDuoc":"Luyện hóa từ tứ phẩm đạo linh bằng Thiên Hoàng Lô","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1362","loai":"xuat-hien","importance":"major","giaiDoan":"Lộ bản chất qua Lưu Nguyệt nghịch chuyển","text":"Vương Lâm dùng Lưu Nguyệt lên đạo linh, nghịch chuyển cực sâu lộ ra bản chất đan dược do chín mặt trời hỗn mang dung hợp thành. Người đạo bào bảy màu nói mục đích nuôi dưỡng thiên đạo. Vương Lâm dùng Thiên Hoàng Lô luyện hóa ba ngày thu lại dạng đan dược kim quang, hút lửa tăng hỏa bổn nguyên.","anchor":"một đan dược màu vàng to bằng đầu người bất ngờ xuất hiện ở phía trên"}]},"nguon":["@c1362"],"dacDiem":"Chín mặt trời hỗn mang dung hợp bởi người đạo bào bảy màu trong tinh không cổ xưa, ép bằng khí bảy màu thành đan dược to bằng đầu người; sau phong ấn vạn năm sức mạnh tiêu tán hơn nửa biến thành dạng đạo linh; không thể nuốt trực tiếp vì sợ nổ tung thân Cổ Thần, cần tế luyện thêm mới đủ linh động."},{"id":"chiec-nhan-xanh-biec","name":"Chiếc nhẫn xanh biếc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Người mặc đạo bào bảy màu"],"trangThai":"Không rõ","blurb":"Chiếc nhẫn xanh biếc đeo trên ngón trỏ tay phải của người đạo bào bảy màu trong cảnh Lưu Nguyệt nghịch chuyển. Pho tượng Vương Lâm sở hữu không có chi tiết này.","detail":"Xuất hiện trên ngón trỏ phải của thân ảnh người đạo bào bảy màu khi Vương Lâm dùng Lưu Nguyệt thuật nghịch chuyển nguồn gốc đạo linh. Đây là điểm khác biệt duy nhất giữa thực thể gốc và pho tượng mà Vương Lâm lấy từ Tham Lang — pho tượng không có chiếc nhẫn. Ý nghĩa và công năng chưa được tiết lộ.","nguon":["@c1362"]},{"id":"dai-cao-bac-ba","name":"Đài cao bậc ba","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bậc ba (gần đột phá bậc bốn)","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Đài cao màu tím đoạt từ Linh Động Thượng Nhân, được Vương Lâm dung nhập thêm 312 ấn ký từ đài bậc hai, tổng hơn 900 ấn ký, gần đột phá bậc bốn.","detail":"Đài cao màu tím, đoạt từ Linh Động Thượng Nhân. Vương Lâm rút 312 ấn ký từ đài bậc hai của Chu Công dung nhập vào, tổng ấn ký hơn 900, màu tím gần thành đen, có dấu hiệu đột phá lên bậc bốn.","congNang":["Bảo vật phòng thủ và di chuyển trong cổ mộ, tích lũy ấn ký càng nhiều càng mạnh"],"chuSoHuu":[{"ten":"Linh Động Thượng Nhân","tuChuong":"","denChuong":"@c1362","cachCoDuoc":"","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1362","denChuong":"","cachCoDuoc":"Đoạt từ Linh Động Thượng Nhân","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1363","loai":"nang-cap","importance":"normal","giaiDoan":"Dung nhập 312 ấn ký từ đài bậc hai","text":"Vương Lâm rút 312 ấn ký từ đài bậc hai của Chu Công dung nhập vào đài bậc ba, tổng hơn 900 ấn ký, màu tím gần thành đen, có dấu hiệu đột phá bậc bốn.","anchor":"số lượng ấn ký đã lên tới hơ chín trăm, màu tím trên đó gần như trở thành màu đen"}]},"capNhatToi":"@c1363","nguon":["@c1363"]},{"id":"dai-cao-bac-hai-chu-cong","name":"Đài cao bậc hai (của Chu Công)","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bậc hai","soHuu":["Chu Công"],"trangThai":"da-huy","blurb":"Đài cao bậc hai của Chu Công, có 312 ấn ký. Bị Vương Lâm rút hết ấn ký, đài tan vỡ.","detail":"Đài cao bậc hai chứa 312 ấn ký, thuộc sở hữu lão già Chu Công. Bị Vương Lâm rút toàn bộ ấn ký dung nhập vào đài bậc ba, sau đó đài tan vỡ.","congNang":["Chứa 312 ấn ký"],"chuSoHuu":[{"ten":"Chu Công","tuChuong":"","denChuong":"@c1363","cachCoDuoc":"","trangThai":"da-mat"}],"tabs":{"tienTrinh":[{"chuong":"@c1363","loai":"doi-chu","importance":"normal","giaiDoan":"Bị rút ấn ký, tan vỡ","text":"Bị Vương Lâm uy hiếp đoạt từ Chu Công, rút hết 312 ấn ký dung nhập vào đài bậc ba, đài tan vỡ.","anchor":"trên đó có tổng cộng ba trăm mười hai ấn ký"}]},"capNhatToi":"@c1363","nguon":["@c1363"]},{"id":"tu-pham-moc-dao-linh","name":"Tứ phẩm mộc đạo linh","cn":"四品木道灵","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Tứ phẩm","soHuu":["Đại Hoang Thượng Nhân"],"trangThai":"Đại Hoang nhận lại từ Diệu Âm","blurb":"Mộc đạo linh tứ phẩm bên trong cổ mộ, Đại Hoang phá cấm chế để lấy nhưng bị Diệu Âm cướp, sau được trả lại qua kế li gián.","detail":"Bảo vật nằm trong vùng đất phong ấn của cổ mộ, Đại Hoang Thượng Nhân là người đầu tiên tới phá giải cấm chế để thu lấy. Diệu Âm Đạo Tôn đánh lén cướp mất. Sau đó Diệu Âm dùng kế li gián, biến đạo linh từ hình dạng thanh xà ngàn trượng thành đan dược to bằng đầu người ném trả Đại Hoang để đổi lấy việc Đại Hoang rời đi. Đại Hoang nhận đạo linh nhưng vẫn quay lại phản bội lời thề, liên thủ với Vương Lâm đánh Diệu Âm. Hương thơm đạo linh tràn ngập, hít vào khiến máu di chuyển nhanh hơn.","nguon":["@c1364"]},{"id":"dai-mo-vuong-lam","name":"Đài mộ Vương Lâm","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cấp 5","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Đài mộ của Vương Lâm trong cổ mộ, trải qua nhiều lần thăng cấp từ cấp ba lên cấp tám. Qua mỗi lần dung nhập ấn ký, đài mộ mở rộng kích thước và khai mở thêm các mảnh bản đồ cổ mộ trong thần thức chủ nhân.","detail":"Ban đầu ở kích thước ba ngàn trượng, đài mộ được Vương Lâm nâng cấp liên tục bằng cách thu thập và dung nhập các ấn ký hình con số. Tại @c1367, Vương Lâm phá hủy đài mộ của Diệu Âm Đạo Tôn lấy ký hiệu dung nhập, đưa đài mộ đạt cấp bốn (bốn ngàn trượng), sau đó thêm gần trăm ký hiệu thu từ tu sĩ tử vong nâng lên cấp năm (năm ngàn trượng). Đài mộ hoàn toàn chuyển thành màu đen, hòa với sương mù. Thần thức từ đài mộ cấp năm truyền vào, bản đồ trong đầu Vương Lâm mở thêm hai mảnh (tổng năm), vén gần nửa tấm màn cổ mộ. Tại @c1374, Vương Lâm tự tạo hàng trăm ấn ký dung nhập liên tục, đài mộ thăng từ hơn cấp sáu lên cấp bảy rồi cấp tám.","hinhDang":"Đài cao năm ngàn trượng, màu đen hoàn toàn","congNang":["Mở bản đồ cổ mộ trong thần thức chủ nhân, mỗi cấp mới khai mở thêm mảnh bản đồ @c1367","Thăng cấp bằng cách dung nhập ấn ký hình con số — có thể lấy từ đài mộ người khác, từ tu sĩ tử vong, hoặc tự tạo @c1367 @c1374","Kim quang bức lui sương mù cổ mộ khi thăng cấp @c1367","Kích thước mở rộng theo cấp: cấp bốn bốn ngàn trượng, cấp năm năm ngàn trượng @c1367","Hòa với sương mù cổ mộ khi chuyển hoàn toàn thành màu đen @c1367"],"dacDiem":"Màu đen hoàn toàn, hòa với sương mù cổ mộ; kích thước tăng theo cấp bậc, tính tới mốc mới nhất đã đạt cấp tám.","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1367","denChuong":"","cachCoDuoc":"Tự tạo trong vùng đất cổ mộ","trangThai":"dang-co"}],"capNhatToi":"@c1367","tabs":{"tienTrinh":[{"chuong":"@c1367","loai":"nâng cấp","importance":"major","giaiDoan":"Nâng lên cấp năm","phamCap":"Cấp 5","text":"Vương Lâm phá hủy đài mộ Diệu Âm Đạo Tôn lấy ký hiệu dung nhập đạt cấp bốn, thêm gần trăm ký hiệu từ tu sĩ tử vong nâng lên cấp năm (năm ngàn trượng, màu đen). Bản đồ mở thêm hai mảnh, tổng năm, vén gần nửa tấm màn cổ mộ.","anchor":"đài mộ lại ầm vang một lần nữa, độ lớn lại tăng lên, trong nháy mắt đã đạt tới năm ngàn trượng"},{"chuong":"@c1374","loai":"nâng cấp","importance":"major","giaiDoan":"Cấp bảy rồi cấp tám","phamCap":"Cấp tám (8000 trượng)","text":"Vương Lâm tự tạo hàng trăm ấn ký dung nhập liên tục, đài mộ thăng từ hơn cấp sáu lên cấp bảy rồi cấp tám — đài mộ cấp tám đầu tiên trong toàn cổ mộ. Tiêu hao hết Cổ Yêu khí và phá hủy toàn bộ bảo vật Cổ Yêu chiếm được.","anchor":"Đài mộ cấp tám, trong mọi người ở vùng đất cổ mộ, đây là đài mộ cấp tám đầu tiên"}]},"nguon":["@c1367","@c1374"]},{"id":"khuc-xuong-co-than-cuu-tinh","name":"Khúc xương Cổ Thần cửu tinh","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Khúc xương lớn cỡ ba bàn tay được Vương Lâm lấy từ hốc mắt đầu lâu Cổ Thần cửu tinh trong vùng đất cổ mộ.","detail":"Vương Lâm chui vào hốc mắt đầu lâu Cổ Thần cửu tinh lấy ra khúc xương này. Qua khúc xương, hắn suy đoán Cổ Thần cửu tinh này bị giết trong thời Cổ Thần thất tổn thất kiếp.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1369","denChuong":"","cachCoDuoc":"Lấy từ hốc mắt đầu lâu Cổ Thần cửu tinh","trangThai":"dang-co"}],"congNang":["Di cốt Cổ Thần cửu tinh, dùng suy luận về nguồn gốc và niên đại Cổ Thần @c1369"],"nguon":["@c1369"],"tabs":{"tienTrinh":[{"chuong":"@c1369","loai":"xuất hiện","importance":"normal","giaiDoan":"Được lấy từ đầu lâu Cổ Thần","text":"Vương Lâm chui vào hốc mắt đầu lâu Cổ Thần cửu tinh lấy ra khúc xương lớn cỡ ba bàn tay.","anchor":"trong tay hắn lúc này có một khúc xương lớn cỡ ba bàn tay"}]}},{"id":"dau-lau-co-than-cuu-tinh","name":"Đầu lâu Cổ Thần cửu tinh","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":[],"trangThai":"bi-phong-an","blurb":"Đầu lâu khổng lồ của một Cổ Thần cửu tinh bị chôn sâu dưới cánh rừng trong vùng đất cổ mộ, được pho tượng bảy màu phong ấn. Vương Lâm phát hiện di hài này sau khi cày tung nửa cánh rừng, lần đầu tiên tận mắt thấy đầu lâu một Cổ Thần cửu tinh.","detail":"Nửa đầu lâu khổng lồ có chín tinh điểm mờ nhạt, bị vùi sâu dưới lòng đất với cả một cánh rừng mọc phía trên qua không biết bao nhiêu năm tháng. Khi Vương Lâm cày tung nửa cánh rừng, di hài này mới lộ ra. Hắn nhận ra rằng pho tượng bảy màu tồn tại ở nơi đây chính là để phong ấn đầu lâu Cổ Thần cửu tinh này. Đây là lần đầu tiên Vương Lâm thấy đầu lâu của một Cổ Thần cấp cửu tinh, khiến hắn xúc động mạnh vì nhận ra ngay cả Cổ Thần cửu tinh cũng có thể chết.","congNang":["Di hài Cổ Thần cửu tinh bị phong ấn bởi pho tượng bảy màu @c1369"],"nguon":["@c1369"],"tabs":{"tienTrinh":[{"chuong":"@c1369","loai":"xuất hiện","importance":"major","giaiDoan":"Được phát hiện dưới rừng","text":"Vương Lâm cày tung nửa cánh rừng lộ ra đầu lâu khổng lồ Cổ Thần cửu tinh có chín tinh điểm mờ, nhận ra pho tượng bảy màu chính là để phong ấn nó.","anchor":"pho tượng này tồn tại chính là để phong ấn cái đầu của Cổ Thần cửu tinh này"}]},"dacDiem":"Nửa đầu lâu khổng lồ mang chín tinh điểm mờ nhạt, bị chôn vùi dưới lòng đất với cánh rừng mọc phủ bên trên, cần pho tượng bảy màu trấn áp phong ấn."},{"id":"bao-vat-mang-doc","name":"Bảo vật mang độc (đang luyện)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang luyện hóa","blurb":"Bảo vật mang độc mà Vương Lâm dự tính thu được sau khi luyện hóa xong biển độc đen trong Thiên Hoàng Lô, dự kiến uy lực hung mạnh.","detail":"Biển độc đen kịt trong Thiên Hoàng Lô (từ lưỡi Đại Hoàng Thượng Nhân hóa ra, ẩn chứa hồn phách hương hỏa Diệu Âm Đạo Tôn) đang được Vương Lâm luyện hóa bằng phương pháp bay hơi — ngưng tụ — mưa xuống tuần hoàn. Ba ngày sau mặt biển giảm gần nửa, nước đen kịt đến thần thức không xuyên thấu. Vương Lâm nhận định sau khi luyện xong sẽ có bảo vật mang độc uy lực hung mạnh.","congNang":["Dự kiến uy lực hung mạnh (chưa hoàn thành)"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1370","denChuong":"","cachCoDuoc":"Tự luyện hóa từ biển độc trong Thiên Hoàng Lô","trangThai":"dang-luyen"}],"tabs":{"tienTrinh":[{"chuong":"@c1370","loai":"xuất hiện","importance":"normal","giaiDoan":"Đang luyện hóa","text":"Vương Lâm luyện hóa biển độc đen trong Thiên Hoàng Lô, ba ngày biển giảm gần nửa, độc tố cô đặc. Dự tính thu được bảo vật mang độc uy lực hung mạnh.","anchor":"sau khi ta luyện hóa xong sẽ có một bảo vật mang độc uy lực hung mạnh"}]},"nguon":["@c1370"]},{"id":"pho-tuong-ma-than-linh-dong-toc","name":"Pho tượng Ma Thần Linh Động tộc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo / Tượng thần","phamCap":"Không rõ","soHuu":["Linh Động Thượng Nhân"],"trangThai":"đang sử dụng","blurb":"Pho tượng Ma Thần của Linh Động tộc, nằm phía sau Linh Động dưới đáy biển tím trong Thiên Hoàng Lô, phát hào quang vạn trượng, hỗ trợ cải biến hồn phách hương hỏa.","detail":"Pho tượng Ma Thần của Linh Động tộc, song chưởng vờn quanh phát hào quang vạn trượng. Hồn phách hương hỏa bị bao phủ bởi hào quang thì lộ vẻ mê man và giãy giụa, bị cải biến rồi hiến hương hỏa cho Linh Động hấp thụ.","congNang":["Hỗ trợ cải biến hồn phách hương hỏa, khiến hồn phách mê man và hiến hương hỏa cho chủ nhân hấp thụ"],"chuSoHuu":[{"ten":"Linh Động Thượng Nhân","tuChuong":"@c1370","denChuong":"","cachCoDuoc":"Pháp bảo bản tộc Linh Động","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1370","loai":"dùng","importance":"normal","giaiDoan":"Đang sử dụng trong Thiên Hoàng Lô","text":"Pho tượng Ma Thần nằm phía sau Linh Động dưới đáy biển tím, song chưởng vờn quanh phát hào quang vạn trượng, cải biến hồn phách hương hỏa khiến chúng hiến hương hỏa cho Linh Động hấp thụ.","anchor":"Pho tượng này chính là tượng Ma Thần của Linh Động tộc, song chưởng vờn quanh"}]},"nguon":["@c1370"]},{"id":"toc-an-phong-diet-toc","name":"Tộc ấn Phong Diệt tộc","cn":"","category":"khac","categoryLabel":"Vật phẩm đặc biệt","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"Tộc ấn của Phong Diệt tộc, được ấn vào mi tâm tộc nhân sau khi vượt qua tế tổ. Tộc ấn gắn liền với tam mệnh thuật và sức mạnh phong ấn tổ tiên, sau bị Vương Lâm rút ra từ mi tâm Phong Chỉ Mạn và thu giữ.","detail":"Tộc ấn Phong Diệt tộc là ấn ký được khắc vào mi tâm tộc nhân sau khi họ sống sót qua nghi thức tế tổ, đánh dấu thân phận thuộc về Phong Diệt tộc. Khi tộc ấn bị mất, người mang ấn không chết, tu vi cũng không suy giảm, chỉ không còn được coi là thành viên của Phong Diệt tộc. Tộc ấn mang trong mình hai thuật lực cốt lõi: tam mệnh thuật — ban cho tộc nhân ba mạng sống, và thuật phong ấn tổ tiên — khi tộc nhân hiến tế tính mạng để mở tộc ấn, sức mạnh phong ấn từ tổ tiên sẽ tràn ra. Vương Lâm sau khi soát hồn Phong Chỉ Mạn đã rút tộc ấn từ mi tâm nàng và thu giữ @c1371.","congNang":["Ban cho tộc nhân ba mạng sống (tam mệnh thuật)","Khi hiến tế tính mạng mở tộc ấn, sức mạnh phong ấn của tổ tiên sẽ tràn ra"],"chuSoHuu":[{"ten":"Phong Chỉ Mạn","tuChuong":"","denChuong":"@c1371","cachCoDuoc":"Tế tổ sống sót được ấn vào mi tâm","trangThai":"mat"},{"ten":"Vương Lâm","tuChuong":"@c1371","denChuong":"","cachCoDuoc":"Rút từ mi tâm Phong Chỉ Mạn","trangThai":"dang-co"}],"capNhatToi":"@c1371","tabs":{"tienTrinh":[{"chuong":"@c1371","loai":"doi-chu","importance":"major","giaiDoan":"Vương Lâm rút từ Phong Chỉ Mạn","text":"Vương Lâm soát hồn Phong Chỉ Mạn rồi rút tộc ấn từ mi tâm nàng. Tộc ấn bị rút không gây chết hay giảm tu vi, chỉ khiến nàng không còn thuộc Phong Diệt tộc.","anchor":"Cầm tộc ấn của Phong Diệt tộc, Vương Lâm trầm mặc trong chốc lát rồi thu lại"}]},"nguon":["@c1371"],"dacDiem":"Được ấn vào mi tâm tộc nhân sau nghi thức tế tổ; khi bị rút đi không gây chết, không giảm tu vi, chỉ khiến người mang ấn mất thân phận Phong Diệt tộc."},{"id":"ngoc-gian-ghi-canh-diet-dieu-am","name":"Ngọc giản ghi cảnh diệt Diệu Âm","cn":"","category":"khac","categoryLabel":"Ngọc giản","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"Ngọc giản ghi hình ảnh cảnh Vương Lâm liên thủ với Đại Hoang thượng nhân diệt phân thân Diệu Âm đạo tôn cùng cảnh Đại Hoang đoạt xá.","detail":"Vương Lâm ném vào mi tâm Phong Chỉ Mạn để cho xem cảnh phân thân Diệu Âm bị diệt, phá tan ảo tưởng được cứu của nàng.","congNang":["Ghi hình ảnh chiến đấu, dùng để uy hiếp/chứng minh"],"capNhatToi":"@c1371","tabs":{"tienTrinh":[{"chuong":"@c1371","loai":"dung","importance":"normal","giaiDoan":"Dùng uy hiếp Phong Chỉ Mạn","text":"Vương Lâm ném ngọc giản vào mi tâm Phong Chỉ Mạn cho xem cảnh phân thân Diệu Âm bị diệt và cảnh Đại Hoang đoạt xá, phá tan hy vọng được cứu.","anchor":"những cảnh tượng có liên quan đến Diệu Âm lập tức xuất hiện trong đầu cô gái"}]},"nguon":["@c1371"]},{"id":"dai-cao-nam-ngan-truong","name":"Đài cao năm ngàn trượng","cn":"","category":"khac","categoryLabel":"Kiến trúc","phamCap":"Không rõ","soHuu":[],"trangThai":"xuất hiện","blurb":"Cái đài cao năm ngàn trượng xuất hiện đột ngột trên bầu trời khu rừng trong cổ mộ, trên đài có đại hán bí ẩn đứng.","detail":"Xuất hiện trong từng trận gợn sóng trên bầu trời khu rừng. Cao năm ngàn trượng, trên đài có một đại hán đang đứng, ngẩn ra khi thấy Vương Lâm.","capNhatToi":"@c1371","tabs":{"tienTrinh":[{"chuong":"@c1371","loai":"xuat-hien","importance":"normal","giaiDoan":"Xuất hiện trên bầu trời khu rừng","text":"Đài cao năm ngàn trượng xuất hiện trong gợn sóng trên bầu trời, trên đài có đại hán bí ẩn đứng.","anchor":"một cái đài cao năm ngàn trượng xuất hiện, ở trên đài cao có một đại hán đang đứng"}]},"nguon":["@c1371"]},{"id":"nhan-hoa-kiem","name":"Nhân Hỏa Kiếm","cn":"人火劍","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Cực cao (bảo vật Đạo Cổ Diệp Mịch)","soHuu":["Đạo Cổ Diệp Mịch"],"trangThai":"bi-phong-an","blurb":"Nhân Hỏa Kiếm là thanh kiếm tàn ác nhất thiên hạ, bảo vật theo Đạo Cổ Diệp Mịch chém giết cả đời, được cất giữ trong Nhân phủ thuộc tam phủ Thiên Địa Nhân. Do giết chóc quá nhiều mà kiếm đã thành ma, bị chính Đạo Cổ để lại ba đạo phong ấn trấn áp.","detail":"Nhân Hỏa Kiếm là pháp bảo gắn liền với Đạo Cổ Diệp Mịch, đã cùng chủ nhân chém giết suốt cả đời. Vì sát phạt quá nặng, kiếm nhiễm nghiệp thành ma. Trước khi Đạo Cổ qua đời, ông để lại ba đạo phong ấn trên thân kiếm nhằm trấn áp ma tính. Kiếm được cất trong Nhân phủ, một trong tam phủ Thiên Địa Nhân của Đạo Cổ Diệp Mịch. Thông tin về Nhân Hỏa Kiếm được truyền qua thanh âm uy nghiêm vào tâm thần Vương Lâm khi hấp thụ đài cao bậc năm, tiết lộ kiếm mang danh thanh kiếm tàn ác nhất thiên hạ @c1373.","congNang":["Kiếm sát phạt cực mạnh"],"nguonGoc":"Bảo vật theo Đạo Cổ Diệp Mịch chém giết cả đời","dacDiem":"Đã thành ma do chém giết quá nhiều, bị ba đạo phong ấn của Đạo Cổ Diệp Mịch trấn áp","chuSoHuu":[{"ten":"Đạo Cổ Diệp Mịch","tuChuong":"@c1373","denChuong":"","cachCoDuoc":"Bảo vật bản thân","trangThai":"phong-an"}],"tabs":{"tienTrinh":[{"chuong":"@c1373","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu tiết lộ","text":"Thông điệp Đạo Cổ Diệp Mịch tiết lộ Nhân phủ chứa Nhân Hỏa Kiếm, thanh kiếm tàn ác nhất thiên hạ, theo Đạo Cổ chém giết cả đời, vì chém giết mà thành ma nên bị ba đạo phong ấn.","anchor":"Nhân phủ có Nhân Hỏa Kiếm, kiếm này theo bổn đạo chém giết cả đời, là một thanh kiếm tàn ác nhất trong thiên hạ"}]},"nguon":["@c1373"]},{"id":"dai-cao-bac-nam-chu-can","name":"Đài cao bậc năm (của Chu Cẩn)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bậc năm","soHuu":["Chu Cẩn","Vương Lâm"],"trangThai":"da-dung","blurb":"Đài cao bậc năm của Chu Cẩn, bị Vương Lâm hấp thụ ấn ký, giúp đài cao Vương Lâm tăng lên sáu ngàn trượng.","detail":"Vương Lâm hấp thụ ấn ký trên đài cao bậc năm của Chu Cẩn, đài cao của hắn chấn động lớn lên tới sáu ngàn trượng, bản đồ trong đầu hiện thêm một tấm, đồng thời nhận được thông điệp thanh âm uy nghiêm của Đạo Cổ Diệp Mịch.","congNang":["Chứa ấn ký và bản đồ cổ mộ"],"chuSoHuu":[{"ten":"Chu Cẩn","tuChuong":"@c1373","denChuong":"@c1373","cachCoDuoc":"Sở hữu ban đầu","trangThai":"mat"},{"ten":"Vương Lâm","tuChuong":"@c1373","denChuong":"","cachCoDuoc":"Hấp thụ ấn ký","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1373","loai":"đổi chủ","importance":"normal","giaiDoan":"Hấp thụ bởi Vương Lâm","text":"Vương Lâm hấp thụ ấn ký đài cao bậc năm Chu Cẩn, đài cao tăng lên sáu ngàn trượng, bản đồ trong đầu hiện thêm một tấm.","anchor":"cái đài cao này ầm vang chấn động, một lượng lớn ấn ký trên đó bay ra, hướng thẳng tới Vương Lâm"}]},"nguon":["@c1373"]},{"id":"ho-lo-co-yeu","name":"Hồ lô Cổ Yêu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Hồ lô bảo vật của Cổ Yêu, bên trong chứa Cổ Yêu lực, được Vương Lâm lấy ra gõ lên để lấy yêu khí dung hợp tam tộc lực.","detail":"Hồ lô của một tu sĩ ở vùng đất bị phong ấn thứ nhất từng giao cho Vương Lâm để giữ tính mạng. Là bảo vật của Cổ Yêu, bên trong chứa Cổ Yêu lực. Vương Lâm gõ lên hồ lô, yêu khí tản ra dùng dung hợp cùng Cổ Thần lực và Cổ Ma lực.","congNang":["Chứa Cổ Yêu lực"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1373","denChuong":"","cachCoDuoc":"Tu sĩ ở vùng phong ấn thứ nhất giao","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1373","loai":"dùng","importance":"normal","giaiDoan":"Lấy Cổ Yêu lực dung hợp","text":"Vương Lâm lấy hồ lô ra gõ lên, yêu khí tản ra dùng dung hợp cùng Cổ Thần lực và Cổ Ma lực thành tam tộc lực.","anchor":"Đây là cái hồ lô của một tu sĩ vì giữ tính mạng mà giao cho hắn ở vùng đất bị phong ấn thứ nhất"}]},"nguon":["@c1373"]},{"id":"co-hon-binh","name":"Cổ Hồn Bình","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Bình chứa hồn phách Cổ Ma, Vương Lâm vỗ lên bình lấy hồn phách ra giết để thu Cổ Ma lực.","detail":"Vương Lâm lấy Cổ Hồn Bình từ không gian trữ vật, vỗ lên bình, một hồn phách Cổ Ma bay ra gào thét thê lương, bị Vương Lâm giết lấy Cổ Ma lực dùng dung hợp tam tộc lực.","congNang":["Chứa hồn phách Cổ Ma"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1373","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1373","loai":"dùng","importance":"normal","giaiDoan":"Lấy Cổ Ma lực","text":"Vương Lâm vỗ lên Cổ Hồn Bình, hồn phách Cổ Ma bay ra bị giết lấy Cổ Ma lực dung hợp tam tộc lực.","anchor":"lấy ra Cổ Hồn Bình, tay phải vỗ lên đó, trong tiếng gào thét thê lương, từ bên trong lập tức bay ra một hồn phách của Cổ Ma"}]},"nguon":["@c1373"]},{"id":"dau-an-con-so","name":"Dấu ấn con số","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Ký hiệu trên mi tâm người vào cổ mộ, ẩn chứa sức mạnh cho phép tồn tại trong cổ mộ. Không có dấu ấn sẽ bị quy tắc cổ mộ xóa bỏ.","detail":"Dấu ấn con số nằm trên mi tâm mỗi người khi vào cổ mộ, bên trong ẩn chứa sức mạnh cực kỳ cổ quái giúp tồn tại trong cổ mộ. Cổ Thần, Cổ Ma, Cổ Yêu không cần dấu ấn này. Vương Lâm quan sát hàng trăm dấu ấn rồi dùng tam tộc lực dung hợp xóa thành công dấu ấn trên mi tâm thiếu nữ Phong Diệt tộc, lập tức sương mù sôi trào tấn công thiếu nữ, quy tắc cổ mộ muốn xóa sự tồn tại không có dấu ấn.","congNang":["Cho phép tồn tại trong cổ mộ","Mất dấu ấn sẽ bị sương mù cổ mộ xóa bỏ"],"nguon":["@c1373"]},{"id":"dai-mo-cap-tam-vuong-lam","name":"Đài mộ cấp tám (của Vương Lâm)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Đài mộ cấp tám","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Đài mộ cấp tám của Vương Lâm cao tám ngàn trượng, tỏa kim quang rực rỡ, là đài mộ cấp tám đầu tiên xuất hiện trong cổ mộ. Sở hữu tốc độ sánh ngang cao thủ bước thứ ba, có khả năng cảm ứng chính xác vị trí các đài mộ khác và nắm toàn bộ đường đi trong bản đồ thứ tám.","detail":"Khi nâng cấp đạt tám ngàn trượng, đài mộ tỏa kim quang rực rỡ tựa mặt trời, trở thành đài mộ cấp tám đầu tiên trong toàn cổ mộ. Việc đạt cấp tám đồng thời mở ra bản đồ thứ tám, phơi lộ hơn phân nửa cổ mộ. Chủ nhân đài mộ cấp tám có thể cảm ứng chính xác vị trí của các đài mộ khác, trong khi đối phương chỉ cảm ứng được một cách mơ hồ, tạo nên lợi thế tuyệt đối trong việc truy tìm hoặc né tránh. Sương mù trong cổ mộ tự động tránh ra trước đài mộ, không thể ngăn cản đường đi. Muốn tiếp tục nâng lên cấp chín đòi hỏi lượng dấu ấn ký hiệu rất lớn, lượng pháp khí Cổ Yêu còn lại không đủ để đáp ứng.","congNang":["Tốc độ di chuyển sánh ngang cao thủ bước thứ ba @c1375","Cảm ứng chính xác vị trí các đài mộ khác, trong khi đối phương chỉ cảm ứng mơ hồ @c1375","Nắm toàn bộ đường đi trong bản đồ thứ tám @c1375","Sương mù trong cổ mộ tự động tránh ra, không cản trở @c1375","Mở bản đồ thứ tám, lộ hơn phân nửa cổ mộ @c1375"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1375","denChuong":"","cachCoDuoc":"Nâng cấp từ đài mộ cấp bảy","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1375","loai":"nang-cap","importance":"major","giaiDoan":"Đạt cấp tám — đài mộ đầu tiên trong cổ mộ","text":"Đài mộ đạt cấp tám (tám ngàn trượng), là đài mộ cấp tám đầu tiên, tỏa kim quang. Mở bản đồ thứ tám, lộ hơn phân nửa cổ mộ. Bốn cao thủ đồng loạt chuyển hướng truy sát.","anchor":"Tốc độ của đài mộ cấp tám có thể so sánh với cao thủ bước thứ ba"}]},"capNhatToi":"@c1375","nguon":["@c1375"],"uyLuc":"Đài mộ tám ngàn trượng tỏa kim quang rực rỡ, tốc độ sánh ngang cao thủ bước thứ ba, sương mù tự tránh, là đài mộ cấp tám đầu tiên trong toàn cổ mộ.","dacDiem":"Cao tám ngàn trượng, tỏa kim quang rực rỡ như mặt trời, sương mù tự động né tránh trước đài mộ."},{"id":"dai-mo-cap-chin-vuong-lam","name":"Đài mộ cấp chín (của Vương Lâm)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cấp chín (9000 trượng)","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Đài mộ cấp chín là đài mộ cấp cao nhất từng xuất hiện trong cổ mộ, được nâng từ đài mộ cấp tám (tám ngàn trượng) lên chín ngàn trượng nhờ hấp thụ toàn bộ ký hiệu dung hợp ba bộ tộc Cổ Yêu, Cổ Ma và Cổ Thần. Tuy nhiên, ngay sau khi đạt thành, đài mộ bị hai cánh tay khổng lồ đồng thời đánh lên phá hủy hoàn toàn.","detail":"Đài mộ cấp chín của Vương Lâm vốn là đài mộ cấp tám cao tám ngàn trượng. Sau khi hấp thụ toàn bộ ký hiệu dung hợp của ba bộ tộc Cổ Yêu, Cổ Ma và Cổ Thần, đài mộ chấn động kịch liệt, tăng trưởng từ 8200 trượng lên đến 9000 trượng, chính thức đạt cấp chín — trở thành đài mộ cấp chín đầu tiên trong lịch sử cổ mộ. Khi đạt cấp chín, kim quang trên thân đài mộ tiêu tán hoàn toàn, bề mặt không còn bất cứ màu sắc nào, toàn thân run rẩy kịch liệt. Tuy nhiên, đài mộ cấp chín chưa kịp phát huy sức mạnh thì hai cánh tay khổng lồ đồng thời đánh lên; đài mộ từng tầng tan vỡ hóa đá vụn, bị phá hủy hoàn toàn.","congNang":["Là đài mộ cấp cao nhất trong cổ mộ, đạt cấp chín nhờ hấp thụ ký hiệu dung hợp ba bộ tộc Cổ Yêu, Cổ Ma, Cổ Thần @c1377"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1377","denChuong":"@c1377","cachCoDuoc":"Tự nâng cấp từ đài mộ cấp tám bằng ký hiệu ba bộ tộc","trangThai":"hong"}],"tabs":{"tienTrinh":[{"chuong":"@c1377","loai":"nâng cấp","importance":"major","giaiDoan":"Thành hình và bị phá hủy","text":"Đài mộ tám ngàn trượng hấp thụ ký hiệu ba bộ tộc tăng lên chín ngàn trượng đạt cấp chín — đầu tiên trong cổ mộ. Hai cánh tay khổng lồ đồng thời đánh, đài mộ từng tầng tan vỡ hóa đá vụn bị phá hủy.","anchor":"Tám ngàn hai trăm trượng, tám ngàn bốn trăm trượng…….cho đến chín ngàn trượng"}]},"nguon":["@c1377"],"uyLuc":"Sức mạnh thực sự chưa kịp thể hiện do bị phá hủy ngay sau khi thành hình.","dacDiem":"Khi đạt cấp chín, kim quang trên đài mộ tiêu tán hoàn toàn, bề mặt không còn bất cứ màu sắc nào, toàn thân run rẩy kịch liệt; cao chín ngàn trượng, là đài mộ cấp chín đầu tiên trong cổ mộ."},{"id":"soi-to-den-nu-tu-ao-hong","name":"Sợi tơ đen (nữ tử áo hồng)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nữ tử áo hồng (bạn đồng hành Thác Sâm)"],"trangThai":"dang-co","blurb":"Sợi tơ đen phun từ sương mù hồng nhạt, cuốn quanh thân thể giúp nữ tử áo hồng né tránh cánh tay khổng lồ.","detail":"Nữ tử áo hồng phun ra đám sương mù hồng nhạt chứa sợi tơ đen, sợi tơ cuốn quanh thân thể giúp di chuyển ngàn trượng để né cánh tay khổng lồ, tuy vẫn bị đầu ngón tay chạm phải gây thương tích.","nguon":["@c1377"]},{"id":"quang-sang-hinh-tron-thien-phu","name":"Quầng sáng hình tròn (trên ghế đài đá)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":[],"trangThai":"Nằm trên ghế trống đỉnh đài đá trong Thiên Phủ","blurb":"Vật thể bí ẩn trên ngai ghế trống ở đỉnh đài đá trong Thiên Phủ đại điện, phát ánh sáng nhẹ nhàng, lẳng lặng trôi.","detail":"Trên cái ghế lớn ở đỉnh đài đá trong Thiên Phủ đại điện không có người ngồi, chỉ có quầng sáng hình tròn phát ra ánh sáng nhẹ nhàng, lẳng lặng trôi. Phía trước ghế có lỗ hổng lớn chứa khí kinh thiên, là dấu tích của kiếm hoặc tiễn năm xưa đâm thẳng vào người từng ngồi trên ghế.","nguon":["@c1378"]},{"id":"chiec-ghe-tren-dai","name":"Chiếc ghế trên đài","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (vượt xa bước thứ ba)","soHuu":[],"trangThai":"trong cổ mộ","blurb":"Chiếc ghế khổng lồ trên đài cao trong đại điện cổ mộ. Khi Vương Lâm ngồi lên, ghế phóng ra yêu khí và ma khí kích hoạt mười tám tinh điểm Cổ Thần, mang lại uy áp bá đạo vượt xa bước thứ ba, thậm chí Thái Cổ Ngũ Tôn cũng không sánh được.","detail":"Chiếc ghế nằm trên đài cao trong đại điện cổ mộ, bao quanh bởi mấy vạn tu sĩ hóa đá, tám rồng hóa đá và vô số chiến xa. Dưới chân đài có khe lớn — dấu tích của một mũi tên cổ xưa từng xuyên qua mọi thứ đâm vào người ngồi trên ghế. Khi Vương Lâm ngồi lên dưới lực dẫn dắt, yêu khí chảy vào mắt trái, ma khí chảy vào mắt phải, kích hoạt mười hai tinh điểm hư ảo cộng sáu tinh điểm mi tâm thành mười tám tinh điểm vận hành trên quỹ đạo đồng nhất. Uy áp tỏa ra khi đó vượt xa bước thứ ba, Chu Cẩn nhận định đây là sức mạnh Vương Lâm đi mượn chứ không phải bản thân hắn sở hữu.","congNang":["Phóng ra yêu khí vào mắt trái và ma khí vào mắt phải của người ngồi, kích hoạt mười tám tinh điểm Cổ Thần vận hành đồng nhất @c1379","Mang lại uy áp bá đạo vượt xa bước thứ ba, thậm chí Thái Cổ Ngũ Tôn cũng không sánh được @c1379"],"tabs":{"tienTrinh":[{"chuong":"@c1379","loai":"dùng","importance":"major","giaiDoan":"Vương Lâm ngồi lên ghế","text":"Vương Lâm ngồi lên ghế dưới lực dẫn dắt, yêu khí và ma khí phóng ra kích hoạt mười tám tinh điểm đồng nhất, uy áp bá đạo bức Linh Động Thượng Nhân và Chu Cẩn quỳ phục.","anchor":"Là sức mạnh mượn được từ trên cái ghế quỷ dị này"}]},"nguon":["@c1379"],"uyLuc":"Uy áp tỏa ra khi ngồi trên ghế vượt xa bước thứ ba, ngay cả Thái Cổ Ngũ Tôn cũng không thể sánh bằng.","dacDiem":"Ghế khổng lồ đặt trên đài cao trong đại điện cổ mộ, bao quanh bởi mấy vạn tu sĩ hóa đá, tám rồng hóa đá, vô số chiến xa, và dưới chân đài có khe lớn do một mũi tên cổ xưa từng xuyên qua đâm vào người ngồi trên ghế."},{"id":"chiec-o","name":"Chiếc ô","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Văn sĩ trung niên cầm ô"],"trangThai":"hóa đá (cùng chủ nhân)","blurb":"Chiếc ô do văn sĩ trung niên bí ẩn cầm, đã mở ra, xuất hiện cả ở thi thể hóa đá lẫn trong ảo cảnh nghịch chuyển thời gian của đại chiến cổ xưa.","detail":"Chiếc ô nằm trong tay tu sĩ đặc biệt (văn sĩ trung niên) đối diện chiếc ghế trên đài. Trong ảo cảnh nghịch chuyển thời gian, chủ nhân cầm ô đã mở xuyên qua đám tu sĩ đang xông lên, giơ tay chỉ về người ngồi trên ghế. Thi thể hóa đá vẫn giữ tư thế cầm ô lơ lửng giữa không trung.","tabs":{"tienTrinh":[{"chuong":"@c1379","loai":"xuất hiện","importance":"normal","giaiDoan":"Xuất hiện trong thi thể hóa đá và ảo cảnh","text":"Chiếc ô do tu sĩ đặc biệt cầm, đã mở, lơ lửng giữa không trung đối diện chiếc ghế trên đài. Trong ảo cảnh nghịch chuyển thời gian, chủ nhân cầm ô yên lặng xuyên qua đám tu sĩ.","anchor":"tu sĩ này cầm trong tay một cái ô, sau khi mở ô lơ lửng giữa không trung"}]},"nguon":["@c1379"]},{"id":"cung-chin-dao-phong-an-ly-quang","name":"Cây cung chín đạo phong ấn","cn":null,"aliases":["Cung của Lý Quảng","Cung kinh thiên"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lý Quảng","Tu sĩ bảy màu"],"trangThai":"Bị tu sĩ bảy màu gỡ mang đi, hứa đưa về tông môn Lý Quảng","blurb":"Cung lớn làm từ khúc xương khô, khắc nhật nguyệt, dây cung phát khí tức tang thương, có chín đạo phong ấn. Lý Quảng dùng bắn mũi tên xuyên mọi trở ngại, ghim mắt trái Đạo cổ Diệp Mịch.","detail":"Cây cung lớn được chế từ một khúc xương khô, trên thân khắc nhật nguyệt, dây cung phát ra khí tức tang thương, mang chín đạo phong ấn. Lý Quảng nhắm mắt kéo cung, buông tay trừng mắt bắn ra một mũi tên xuyên qua ánh sáng bảy màu của nam tử cầm ô, xuyên qua khí tức đầu lâu đạo cổ, ghim vào mắt trái đầu lâu khổng lồ (hư ảnh Diệp Mịch), mang con mắt đẫm máu bay vào hư vô. Sau trận chiến, tu sĩ bảy màu gỡ cung từ tay Lý Quảng đã hóa đá, hứa sẽ đưa cung về tông môn của Lý Quảng sau khi thiên đạo trưởng thành.","nguon":["@c1380"]},{"id":"hai-muoi-la-co-tuc-diep","name":"Hai mươi lá cổ Tức Diệp","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Hai mươi lá cổ Tức Diệp được Vương Lâm triệu từ mi tâm, hóa ô quang phong ấn lỗ hổng cung điện ngăn Thác Sâm.","detail":"Vương Lâm điểm mi tâm triệu ra hai mươi lá cổ Tức Diệp, vung tay trái phóng về phía trước hóa thành từng đạo ô quang phong ấn lỗ hổng cung điện. Thác Sâm đấm vỡ ba lá, còn mười bảy lá phong ấn.","congNang":["Phong ấn lỗ hổng, ngăn chặn đối thủ xâm nhập"],"dacDiem":"Từ mi tâm Vương Lâm triệu ra, hóa ô quang","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1381","denChuong":"","cachCoDuoc":"Triệu từ mi tâm","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1381","loai":"dùng","importance":"normal","giaiDoan":"Phong ấn lỗ hổng cung điện","text":"Vương Lâm triệu hai mươi lá cổ Tức Diệp từ mi tâm phong ấn lỗ hổng cung điện ngăn Thác Sâm. Thác Sâm đấm vỡ ba lá.","anchor":"hai mươi lá cổ Tức Diệp xuất hiện. Theo tay trái hắn vung về phía trước hai mươi lá cổ Tức Diệp này hóa thành từng đạo ô quang"}]},"nguon":["@c1381"]},{"id":"chiec-ghe-truyen-thua","name":"Chiếc ghế truyền thừa","cn":"","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Trọng bảo","soHuu":[],"trangThai":"dang-co","blurb":"Chiếc ghế trên đài cao tầng ba cổ mộ, nơi truyền thừa Cổ Thần. Lực phản chấn cực mạnh theo mỗi nhịp thở, có thể phá hủy hoàn toàn thân thể người ngồi. Sau khi Vương Lâm thành thất tinh Cổ Thần, chiếc ghế hóa thành đài mộ, phóng đại thần thức vô số vạn lần và cho cảm nhận ý chí Đạo cổ lưu lại trong tầng ba cổ mộ.","detail":"Chiếc ghế nằm trên đài cao tại tầng ba cổ mộ, là vật then chốt trong quá trình truyền thừa Cổ Thần. Khi Vương Lâm ngồi lên, mỗi nhịp thở đều sinh lực phản chấn khủng khiếp, tăng dần theo từng nhịp. Suốt mười tám nhịp thở, lực phản chấn mạnh đến mức đè nát cả thất tinh Cổ Thần trước khi hoàn thành, nhịp thứ mười tám phá hủy hoàn toàn thân thể Vương Lâm. Sau khi thành thất tinh Cổ Thần, chiếc ghế sinh ra mối liên hệ quỷ dị với thần thức Vương Lâm, hóa thành đài mộ — phóng đại thần thức vô số vạn lần, cho phép cảm nhận toàn bộ tầng ba cổ mộ cùng ý chí Đạo cổ Diệp Mịch lưu lại @c1381.","congNang":["Truyền thừa Cổ Thần lực qua tinh điểm theo từng nhịp thở, kèm lực phản chấn tăng dần","Phóng đại thần thức vô số vạn lần khi hóa thành đài mộ @c1381","Hóa đài mộ liên hệ ý chí Đạo cổ Diệp Mịch, cho cảm nhận toàn bộ tầng ba cổ mộ @c1381"],"dacDiem":"Lực phản chấn cực mạnh, đè nát cả thất tinh Cổ Thần trước khi hoàn thành; sau truyền thừa hóa thành đài mộ, sinh liên hệ quỷ dị với thần thức người thụ lĩnh.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1381","denChuong":"","cachCoDuoc":"Ngồi lên ghế tiếp nhận truyền thừa","trangThai":"lien-he"}],"tabs":{"tienTrinh":[{"chuong":"@c1381","loai":"khai phong","importance":"major","giaiDoan":"Hoàn thành truyền thừa, hóa đài mộ","text":"Chiếc ghế hóa thành đài mộ, phóng đại thần thức Vương Lâm vô số vạn lần, cho cảm nhận toàn bộ tầng ba cổ mộ và ý chí Đạo cổ Diệp Mịch.","anchor":"chiếc ghế này dường như hóa thành một đài mộ, Vương Lâm ngồi ở trên đó, trong đầu bất ngờ xuất hiện toàn bộ hình ảnh của cả tầng thứ ba của cổ mộ"}]},"nguon":["@c1381"],"uyLuc":"Lực phản chấn cực mạnh, đè nát cả thất tinh Cổ Thần trước khi hoàn thành, nhịp thứ mười tám phá hủy hoàn toàn thân thể người ngồi."},{"id":"dai-lua-tu-phi","name":"Dải lụa của Tứ phi","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Phấn y nữ tử"],"trangThai":"hong","blurb":"Dải lụa là pháp bảo do Viễn Cổ Tiên Tôn ban tặng cho tứ phi (nữ tử phong tình), có khả năng phòng thủ và né tránh. Tại @c1382, dải lụa bị tiếng rống chứa thần niệm Đạo Cổ Diệp Mịch hủy diệt hoàn toàn, không thể bảo vệ chủ nhân.","detail":"Dải lụa là pháp bảo được Viễn Cổ Tiên Tôn ban tặng cho tứ phi — nữ tử phong tình. Pháp bảo này từng phát huy tác dụng phòng thủ, giúp tứ phi né tránh được cánh tay khổng lồ. Tuy nhiên, khi đối mặt với tiếng rống mà Vương Lâm phát ra nhờ thần niệm Đạo Cổ Diệp Mịch, dải lụa bị tan vỡ hoàn toàn, không còn khả năng che chở cho chủ nhân (@c1382).","nguon":["@c1382"],"congNang":["Phòng thủ, né tránh — từng đỡ được cánh tay khổng lồ"],"chuSoHuu":[{"ten":"Phấn y nữ tử","tuChuong":"@c1382","denChuong":"","cachCoDuoc":"Viễn Cổ Tiên Tôn ban tặng","trangThai":"hong"}],"tabs":{"tienTrinh":[{"chuong":"@c1382","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Bị tiếng rống hủy diệt","phamCap":"Không rõ","text":"Dải lụa do Viễn Cổ Tiên Tôn ban tặng cho tứ phi bị tiếng rống từ thần niệm Đạo Cổ Diệp Mịch tan vỡ hoàn toàn, không bảo vệ được chủ nhân.","anchor":"dải lụa này là do Viễn cổ Tiên Tôn ban tặng"}]}},{"id":"pho-tuong-co-ma-ngan-truong","name":"Pho tượng Cổ Ma cao ngàn trượng","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-dung","blurb":"Thi thể hóa đá của Cổ Ma trong ba bộ tộc cổ đại, nằm trong cung điện tầng ba cổ mộ. Vẫn giữ sự dữ tợn lúc sống, chỉ có chút khí tức Cổ Ma, không phải vương tộc.","detail":"Pho tượng Cổ Ma cao ngàn trượng trong cung điện cổ mộ, là thi thể hóa đá của Cổ Ma thuộc ba bộ tộc cổ đại. Vương Lâm túm lấy đặt trước mặt, dùng ma khí từ mắt phải nhập vào để bổ sung Cổ Ma lực cho việc ngưng tụ Cổ Ma tinh. Thi thể không phải vương tộc, chỉ có chút khí tức Cổ Ma.","congNang":["Cung cấp khí tức Cổ Ma cho ngưng tụ Cổ Ma tinh"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1383","denChuong":"","cachCoDuoc":"Lấy từ cung điện cổ mộ","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1383","loai":"dùng","importance":"normal","giaiDoan":"Vương Lâm dùng bổ sung Cổ Ma lực","text":"Vương Lâm túm pho tượng thi thể Cổ Ma đặt trước mặt, dùng ma khí từ mắt phải nhập vào để bổ sung Cổ Ma lực. Thi thể chỉ có chút khí tức, không đủ hoàn chỉnh Cổ Ma tinh.","anchor":"pho tượng cổ Ma cao ngàn trượng, vẫn còn giữ lại sự dữ tợn lúc còn sống"}]},"nguon":["@c1383"]},{"id":"khoi-ma-tinh-5-6","name":"Khối ma tinh thứ năm và thứ sáu","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","soHuu":["Vương Lâm"],"trangThai":"nguyên vẹn","blurb":"Hai khối ma tinh Cổ Ma bay ra từ mắt phải thi thể Cổ Ma khi thi thể tan vỡ dưới luồng đại lực truyền thừa tầng thứ ba, được Vương Lâm thu lấy.","detail":"Khối ma tinh thứ năm và thứ sáu xuất hiện khi thi thể Cổ Ma trên tay phải Vương Lâm toàn thân chấn động, thân đá tan vỡ hoàn toàn dưới luồng đại lực từ trái tim tầng thứ ba. Tinh điểm Cổ Ma từ mắt phải nhanh chóng chui ra.","nguon":["@c1385"],"tabs":{"tienTrinh":[{"chuong":"@c1385","loai":"xuất hiện","importance":"normal","giaiDoan":"Xuất hiện và được Vương Lâm thu","text":"Thi thể Cổ Ma trên tay phải Vương Lâm tan vỡ dưới luồng đại lực truyền thừa, giải phóng hai khối ma tinh từ mắt phải.","anchor":"tinh điểm Cổ Ma nhanh chóng chui ra! Khối ma tinh thứ năm, thứ sáu đột nhiên xuất hiện!"}]}},{"id":"dia-phu","name":"Địa Phù","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (uy áp vô biên)","soHuu":["Vương Lâm"],"trangThai":"thu-duoc","blurb":"Địa Phù là toà lầu các hoàng kim vốn thuộc về Diệp Mịch (Đạo Cổ), ẩn giấu trong không gian hỗn độn của bản đồ thứ chín cổ mộ tầng nhất. Bên trong có ba đạo hào quang với uy áp vô biên, sau được Vương Lâm dùng ký ức Đạo Cổ truyền thừa mở ra và thu về.","detail":"Địa Phù là một toà lầu các rất lớn màu hoàng kim, nguyên thuộc về Diệp Mịch — tức Đạo Cổ, được cất giấu trong không gian hỗn độn của bản đồ thứ chín nơi cổ mộ tầng nhất. Toà lầu các có ba cửa sổ, bên trong mỗi cửa sổ hiện một đạo hào quang, cửa chính bị khoá. Uy áp toả ra từ nó vô cùng mạnh mẽ. Tại chương @c1386, Vương Lâm nhờ ký ức Đạo Cổ truyền thừa đã mở được Địa Phù, và nhanh chóng thu toàn bộ toà lầu các vào không gian trữ vật trước khi các tu sĩ mạnh khác kịp đến nơi.","hinhDang":"Toà lầu các rất lớn màu hoàng kim, ba cửa sổ","nguonGoc":"Thuộc về Diệp Mịch (Đạo Cổ), ẩn trong bản đồ thứ chín cổ mộ tầng nhất","congNang":["Bên trong chứa ba đạo hào quang, bản chất chưa rõ @c1386","Toả uy áp vô biên @c1386"],"chuSoHuu":[{"ten":"Diệp Mịch","tuChuong":"@c1386","denChuong":"@c1386","cachCoDuoc":"Chủ gốc","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1386","denChuong":"","cachCoDuoc":"Dùng ký ức Đạo Cổ mở và thu trong cổ mộ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1386","loai":"đổi chủ","importance":"major","giaiDoan":"Vương Lâm thu Địa Phù từ cổ mộ","text":"Vương Lâm dùng ký ức Đạo Cổ mở Địa Phù trong bản đồ thứ chín, thu toà lầu các hoàng kim vào không gian trữ vật trước khi Diệu Âm, Cửu Thiên, Đại Hoang kịp đến.","phamCap":"Không rõ","anchor":"một toà lầu các rất lớn màu hoàng kim ở bên trong cái khe chậm rãi hiện ra"}]},"nguon":["@c1386"],"uyLuc":"Toả uy áp vô biên, khiến các tu sĩ mạnh cũng phải chú ý.","dacDiem":"Toà lầu các rất lớn màu hoàng kim, có ba cửa sổ với ba đạo hào quang bên trong, cửa chính bị khoá, ẩn trong không gian hỗn độn của bản đồ thứ chín."},{"id":"truyen-thua-ky-uc-do-ti","name":"Truyền thừa ký ức Đồ Ti","cn":"","category":"khac","categoryLabel":"Ký ức truyền thừa","phamCap":"Đỉnh bát tinh Cổ Thần","soHuu":["Thác Sâm"],"trangThai":"dang-hap-thu","blurb":"Ký ức truyền thừa của Cổ Thần Đồ Ti, đã theo Vương Lâm hơn ngàn năm. Do Đồ Ti chỉ đạt đỉnh bát tinh Cổ Thần, truyền thừa không còn tác dụng với Vương Lâm nên được chủ động hoá thành hào quang trao lại cho Thác Sâm tại @c1386.","detail":"Truyền thừa ký ức của Cổ Thần Đồ Ti, một trong những di sản Vương Lâm mang theo suốt hơn một ngàn năm tu luyện. Vì cảnh giới của Đồ Ti chỉ dừng ở đỉnh bát tinh Cổ Thần, truyền thừa này không thể giúp Vương Lâm tiến thêm, do đó không còn giá trị sử dụng đối với hắn. Tại @c1386, Vương Lâm chủ động hoá truyền thừa thành hào quang và trao cho Thác Sâm. Thác Sâm tiếp nhận và đặt ký ức truyền thừa lên mi tâm để hấp thu. Đây cũng là lần đầu tiên trong đời Thác Sâm nói lời đa tạ.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1386","denChuong":"@c1386","cachCoDuoc":"Lấy từ truyền thừa Đồ Ti năm xưa","trangThai":"da-trao"},{"ten":"Thác Sâm","tuChuong":"@c1386","denChuong":"","cachCoDuoc":"Được Vương Lâm chủ động trao lại","trangThai":"dang-hap-thu"}],"tabs":{"tienTrinh":[{"chuong":"@c1386","loai":"đổi chủ","importance":"major","giaiDoan":"Vương Lâm trao Thác Sâm","text":"Vương Lâm chủ động hoá truyền thừa Đồ Ti thành hào quang trao cho Thác Sâm. Thác Sâm lần đầu đời nói đa tạ, sau trầm tư hoang mang, cuối cùng đặt lên mi tâm hấp thu.","anchor":"đám hào quang này bay thẳng tới Thác Sâm"}]},"nguon":["@c1386"],"congNang":["Chứa toàn bộ ký ức truyền thừa tu luyện của Cổ Thần Đồ Ti, có thể được hấp thu qua mi tâm @c1386","Có thể được chủ hoá thành hào quang để chuyển giao cho người khác @c1386"]},{"id":"thi-the-co-ma","name":"Thi thể Cổ Ma","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-giu","blurb":"Thi thể nguyên vẹn của Cổ Ma bị Vương Lâm thu vào không gian trữ vật.","detail":"Vương Lâm thu thi thể của Cổ Ma vào không gian trữ vật khi dọn dẹp chiến trường trong cung điện trước khi rời cổ mộ.","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1386","denChuong":"","cachCoDuoc":"Thu từ chiến trường cung điện cổ mộ","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c1386","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm thu thi thể","text":"Vương Lâm thu thi thể Cổ Ma vào không gian trữ vật.","anchor":"hắn còn thu thi thể của Cổ Ma kia vào trong không gian trữ vật"}]},"nguon":["@c1386"]}]};
